mapper.select:
/* oms-ordercommon-sql-oracle.xml selectInCotypeList */
SELECT TC.OWKEY
     , TC.COHDKEY 
     , TC.EXTORDERTYPECD 
     , TC.ORDERTYPECD 
     , TC.WKSTATUS
     , TC.ORDERERRCD 
     , TC.ORDERERRCMT

  FROM (
        SELECT REQORDERNO, CLAIMNO-- DLVYEXPCTDAY
          FROM TORDER_INTF_IBORDER_HD
         WHERE IFID = #{interfaceId}
           AND REQUESTDT = #{requestDt}   
       ) TI
  JOIN TORDER_INFO_CO_HD TC
      ON (TI.REQORDERNO = TC.REQORDERNO OR TI.CLAIMNO = TC.CLAIMNO)
    --ON TI.REQORDERNO = TC.REQORDERNO        
   --AND TI.DLVYEXPCTDAY = TC.DLVYEXPCTDAY
   AND TC.IFID = #{interfaceId}
   AND TC.WKSTATUS <> #{cancelWkstatus}
   AND TC.OWKEY = #{owkey}


  FROM (

        SELECT #{item.cohdkey} AS COHDKEY    /*CO번호*/

       ) TI
  JOIN TORDER_INFO_CO_HD TC
    ON TI.COHDKEY = TC.COHDKEY        
   AND TC.WKSTATUS <> #{cancelWkstatus}
   AND TC.OWKEY = #{owkey}

/* oms-ordercommon-sql-oracle.xml selectOutCotypeList */
SELECT TC.OWKEY
     , TC.COHDKEY 
     , TC.EXTORDERTYPECD 
     , TC.ORDERTYPECD 
     , TC.WKSTATUS
     , TC.ORDERERRCD 
     , TC.ORDERERRCMT

  FROM (
        SELECT ORGORDERKEY, CLAIMNO -- DLVYEXPCTDAY
          FROM TORDER_INTF_OBORDER_HD
         WHERE IFID = #{interfaceId}
           AND REQUESTDT = #{requestDt}   
       ) TI
  JOIN TORDER_INFO_CO_HD TC
    ON (TI.ORGORDERKEY = TC.ORGORDERKEY OR TI.CLAIMNO = TC.CLAIMNO)
   --AND TI.DLVYEXPCTDAY = TC.DLVYEXPCTDAY
   AND TC.IFID = #{interfaceId}
   AND TC.WKSTATUS <> #{cancelWkstatus}
   AND TC.OWKEY = #{owkey}


  FROM (

        SELECT #{item.cohdkey} AS COHDKEY    /*CO번호*/

       ) TI
  JOIN TORDER_INFO_CO_HD TC
    ON TI.COHDKEY = TC.COHDKEY        
   AND TC.WKSTATUS <> #{cancelWkstatus}
   AND TC.OWKEY = #{owkey}

/* oms-ordercommon-sql-oracle.xml selectReCreateSoYn */
SELECT TC.OWKEY
     , TC.COHDKEY 
     , TC.EXTORDERTYPECD 
     , TC.ORDERTYPECD 
     , TC.WKSTATUS
     , TC.ORDERERRCD 
     , TC.ORDERERRCMT

  FROM (
        SELECT ORGORDERKEY, CLAIMNO -- DLVYEXPCTDAY
          FROM TORDER_INTF_OBORDER_HD
         WHERE IFID = #{interfaceId}
           AND REQUESTDT = #{requestDt}   
       ) TI
  JOIN TORDER_INFO_CO_HD TC
    ON (TI.ORGORDERKEY = TC.ORGORDERKEY OR TI.CLAIMNO = TC.CLAIMNO)
   --AND TI.DLVYEXPCTDAY = TC.DLVYEXPCTDAY
   AND TC.IFID = #{interfaceId}
   AND TC.WKSTATUS <> #{cancelWkstatus}
   AND TC.OWKEY = #{owkey}


  FROM (

        SELECT #{item.cohdkey} AS COHDKEY    /*CO번호*/

       ) TI
  JOIN TORDER_INFO_CO_HD TC
    ON TI.COHDKEY = TC.COHDKEY        

   AND TC.WKSTATUS NOT IN ('CANCEL', 'ING', 'COMPLETE', 'SEND')
   AND TC.OWKEY = #{owkey}

/* oms-ordercommon-sql-oracle.xml selectInCoOrTypeMappList */ WITH MAPPLIST AS ( SELECT M.EXTORDERTYPECD , M.ORDERTYPECD FROM TORDER_INFO_ORTYPE_MAPPING M JOIN TORDER_MST_ORTYPE OT ON M.OWKEY = OT.OWKEY AND M.ORDERTYPECD = OT.ORDERTYPECD AND M.DELYN = OT.DELYN JOIN TORDER_MST_EXTERN ET ON M.OWKEY = ET.OWKEY AND M.EXTORDERTYPECD = ET.EXTORDERTYPECD AND M.DELYN = ET.DELYN WHERE M.OWKEY = #{owkey} AND M.DELYN = 'N' ) , MAPPDTLIST AS ( SELECT CO.COCOLUMN , CO.ORDERTYPECD , CO.REQRDYN , CO.CDRFRNCVAL , CO.HDDTDIV FROM TORDER_INFO_CO_CHK CO JOIN TORDER_MST_ORTYPE OT ON CO.OWKEY = OT.OWKEY AND CO.ORDERTYPECD = OT.ORDERTYPECD AND OT.DELYN = 'N' WHERE CO.OWKEY = #{owkey} AND CO.HDDTDIV = #{hddtdiv} AND CO.DELYN = 'N' ) SELECT TT.OWKEY , TT.COHDKEY , TT.EXTORDERTYPECD , TT.ORDERTYPECD , TT.REAL_OR_TYPE_CD , TT.REQORDERNO , TT.CLAIMNO FROM ( SELECT T1.OWKEY , T1.COHDKEY , T1.EXTORDERTYPECD , T1.ORDERTYPECD , T1.REAL_OR_TYPE_CD , T1.REQORDERNO , T1.CLAIMNO FROM ( SELECT T.OWKEY , T.COHDKEY , T.EXTORDERTYPECD , T.ORDERTYPECD , T.REAL_OR_TYPE_CD , T.REQORDERNO , T.CLAIMNO FROM ( SELECT TH.OWKEY , TH.COHDKEY , TH.EXTORDERTYPECD , TH.ORDERTYPECD , TH.ORDERTYPECD AS REAL_OR_TYPE_CD , TH.REQORDERNO , TH.CLAIMNO
FROM ( SELECT REQORDERNO, CLAIMNO-- DLVYEXPCTDAY FROM TORDER_INTF_IBORDER_HD WHERE IFID = #{interfaceId} AND REQUESTDT = #{requestDt} ) TI JOIN TORDER_INFO_CO_HD TH ON (TI.REQORDERNO = TH.REQORDERNO OR TI.CLAIMNO = TH.CLAIMNO) AND TH.IFID = #{interfaceId} AND TH.WKSTATUS <> #{cancelWkstatus} AND TH.OWKEY = #{owkey}
FROM (
SELECT #{item.cohdkey} AS COHDKEY /*CO번호*/
) TI JOIN TORDER_INFO_CO_HD TH ON TI.COHDKEY = TH.COHDKEY AND TH.WKSTATUS <> #{cancelWkstatus} AND TH.OWKEY = #{owkey}
) T ) T1 ) TT WHERE 1 = 1

/* oms-ordercommon-sql-oracle.xml selectOutCoOrTypeMappList */ WITH MAPPLIST AS ( SELECT M.EXTORDERTYPECD , M.ORDERTYPECD FROM TORDER_INFO_ORTYPE_MAPPING M JOIN TORDER_MST_ORTYPE OT ON M.OWKEY = OT.OWKEY AND M.ORDERTYPECD = OT.ORDERTYPECD AND M.DELYN = OT.DELYN JOIN TORDER_MST_EXTERN ET ON M.OWKEY = ET.OWKEY AND M.EXTORDERTYPECD = ET.EXTORDERTYPECD AND M.DELYN = ET.DELYN WHERE M.OWKEY = #{owkey} AND M.DELYN = 'N' ) , MAPPDTLIST AS ( SELECT CO.COCOLUMN , CO.ORDERTYPECD , CO.REQRDYN , CO.CDRFRNCVAL , CO.HDDTDIV FROM TORDER_INFO_CO_CHK CO JOIN TORDER_MST_ORTYPE OT ON CO.OWKEY = OT.OWKEY AND CO.ORDERTYPECD = OT.ORDERTYPECD AND OT.DELYN = 'N' WHERE CO.OWKEY = #{owkey} AND CO.HDDTDIV = #{hddtdiv} AND CO.DELYN = 'N' ) SELECT TT.OWKEY , TT.COHDKEY , TT.EXTORDERTYPECD , TT.ORDERTYPECD , TT.REAL_OR_TYPE_CD , TT.ORGORDERKEY FROM ( SELECT T1.OWKEY , T1.COHDKEY , T1.EXTORDERTYPECD , T1.ORDERTYPECD , T1.REAL_OR_TYPE_CD , T1.ORGORDERKEY FROM ( SELECT T.OWKEY , T.COHDKEY , T.EXTORDERTYPECD , T.ORDERTYPECD , T.REAL_OR_TYPE_CD , T.ORGORDERKEY FROM ( SELECT TH.OWKEY , TH.COHDKEY , TH.EXTORDERTYPECD , TH.ORDERTYPECD , TH.ORDERTYPECD AS REAL_OR_TYPE_CD , TH.ORGORDERKEY
FROM ( SELECT ORGORDERKEY, CLAIMNO -- DLVYEXPCTDAY FROM TORDER_INTF_OBORDER_HD WHERE IFID = #{interfaceId} AND REQUESTDT = #{requestDt} ) TI JOIN TORDER_INFO_CO_HD TH ON (TI.ORGORDERKEY = TH.ORGORDERKEY OR TI.CLAIMNO = TH.CLAIMNO) AND TH.IFID = #{interfaceId} AND TH.WKSTATUS <> #{cancelWkstatus} AND TH.OWKEY = #{owkey}
FROM (
SELECT #{item.cohdkey} AS COHDKEY /*CO번호*/
) TI JOIN TORDER_INFO_CO_HD TH ON TI.COHDKEY = TH.COHDKEY AND TH.WKSTATUS <> #{cancelWkstatus} AND TH.OWKEY = #{owkey}
) T ) T1 ) TT WHERE 1 = 1

/* oms-ordercommon-sql-oracle.xml selectInCoDuplicateList_bak */ SELECT TT.OWKEY , TT.REQORDERNO , TT.COHDKEY , TT.CODTKEY , #{errorCode} AS ORDERERRCD , COALESCE(MAX(MM.DISPLAYMSG), #{errorMessage}) AS ORDERERRCMT FROM ( SELECT CH.REQORDERNO , CH.COHDKEY , CD.CODTKEY , CD.OWKEY , CH.IFID , COUNT(1) OVER(PARTITION BY CD.COHDKEY, CD.CODTKEY) AS CNT
FROM ( SELECT DISTINCT REQORDERNO FROM TORDER_INTF_IBORDER_DT WHERE IFID = #{interfaceId} AND REQUESTDT = #{requestDt} ) TI JOIN TORDER_INFO_CO_DT CD ON TI.REQORDERNO = CD.REQORDERNO AND CD.OWKEY = #{owkey} JOIN TORDER_INFO_CO_HD CH ON CD.OWKEY = CH.OWKEY AND CD.COHDKEY = CH.COHDKEY AND CD.WKSTATUS <> #{cancelWkstatus}
FROM (
SELECT #{item.cohdkey} AS COHDKEY /*CO번호*/
) TI JOIN TORDER_INFO_CO_HD CH ON CH.OWKEY = #{owkey} AND TI.COHDKEY = CH.COHDKEY AND CH.WKSTATUS <> #{cancelWkstatus} JOIN TORDER_INFO_CO_DT CD ON CH.OWKEY = CD.OWKEY AND CH.COHDKEY = CD.COHDKEY AND CD.WKSTATUS <> #{cancelWkstatus}
) TT LEFT JOIN TADMIN_MST_MULAAPMSG_DT MM ON MM.MULAAPMSGHDKEY = 'MSG_' || #{errorCode} AND MM.LAKEY = COALESCE(#{lakey}, 'KOR') WHERE TT.CNT > 1 AND TT.IFID = #{interfaceId} GROUP BY TT.OWKEY, TT.REQORDERNO, TT.COHDKEY, TT.CODTKEY

/* oms-ordercommon-sql-oracle.xml selectInCoDuplicateList */ SELECT TT.OWKEY , TT.REQORDERNO , TT.COHDKEY , TT.CODTKEY , #{errorCode} AS ORDERERRCD , COALESCE(MAX(MM.DISPLAYMSG), #{errorMessage}) AS ORDERERRCMT FROM ( SELECT CH.REQORDERNO , CH.CLAIMNO , CH.COHDKEY , CD.CODTKEY , CD.OWKEY , CH.IFID , COUNT(1) OVER(PARTITION BY CD.COHDKEY, CD.CODTKEY) AS CNT
FROM TORDER_INFO_CO_DT CD JOIN TORDER_INFO_CO_HD CH ON CD.OWKEY = CH.OWKEY AND CD.COHDKEY = CH.COHDKEY AND CD.WKSTATUS <> #{cancelWkstatus} AND CD.OWKEY = #{owkey} AND CH.IFID = #{interfaceId}
FROM (
SELECT #{item.cohdkey} AS COHDKEY /*CO번호*/
) TI JOIN TORDER_INFO_CO_HD CH ON CH.OWKEY = #{owkey} AND TI.COHDKEY = CH.COHDKEY AND CH.WKSTATUS <> #{cancelWkstatus} JOIN TORDER_INFO_CO_DT CD ON CH.OWKEY = CD.OWKEY AND CH.COHDKEY = CD.COHDKEY AND CD.WKSTATUS <> #{cancelWkstatus}
) TT LEFT JOIN TADMIN_MST_MULAAPMSG_DT MM ON MM.MULAAPMSGHDKEY = 'MSG_' || #{errorCode} AND MM.LAKEY = COALESCE(#{lakey}, 'KOR') WHERE TT.CNT > 1 AND TT.IFID = #{interfaceId} GROUP BY TT.OWKEY, TT.REQORDERNO, TT.CLAIMNO, TT.COHDKEY, TT.CODTKEY

/* oms-ordercommon-sql-oracle.xml selectOutCoDuplicateList */ SELECT TT.OWKEY , TT.ORGORDERKEY , TT.COHDKEY , #{errorCode} AS ORDERERRCD , COALESCE(MAX(MM.DISPLAYMSG), #{errorMessage}) AS ORDERERRCMT FROM ( SELECT CH.ORGORDERKEY , CH.COHDKEY , CH.OWKEY , CH.IFID , COUNT(1) OVER(PARTITION BY CH.ORGORDERKEY) AS CNT
FROM ( SELECT ORGORDERKEY , CLAIMNO FROM TORDER_INTF_OBORDER_HD WHERE IFID = #{interfaceId} AND REQUESTDT = #{requestDt} ) TI JOIN TORDER_INFO_CO_HD CH ON CH.OWKEY = #{owkey} AND CH.ORGORDERKEY = TI.ORGORDERKEY AND CH.WKSTATUS NOT IN ('CANCEL' ,'ERROR' )
AND CH.EXTORDERTYPECD = #{extordertypecd} AND CH.CLAIMNO = TI.CLAIMNO
FROM (
SELECT #{item.cohdkey} AS COHDKEY /*CO번호*/
) TI JOIN TORDER_INFO_CO_HD CH ON CH.OWKEY = #{owkey} AND TI.COHDKEY = CH.COHDKEY AND CH.WKSTATUS <> #{cancelWkstatus} JOIN TORDER_INFO_CO_DT CD ON CH.OWKEY = CD.OWKEY AND CH.COHDKEY = CD.COHDKEY AND CD.WKSTATUS <> #{cancelWkstatus}
) TT LEFT JOIN TADMIN_MST_MULAAPMSG_DT MM ON MM.MULAAPMSGHDKEY = 'MSG_' || #{errorCode} AND MM.LAKEY = COALESCE(#{lakey}, 'KOR') WHERE TT.CNT > 1
GROUP BY TT.OWKEY, TT.ORGORDERKEY, TT.COHDKEY

		/* oms-ordercommon-sql-oracle.xml selectIfMappingList */
		SELECT UC.COLUMN_NAME AS COCOLUMN
             , MAX(IM.IFCOL) AS IFCOLUMN
          FROM USER_TAB_COLUMNS UC
          LEFT JOIN TORDER_INFO_IF_MAPPING IM
            ON UC.COLUMN_NAME = IM.COCOL 
           AND IM.OWKEY = #{owkey}
           AND IM.EXTORDERTYPECD = #{extordertypecd}
           AND IM.HDDTDIV  = #{hddtdiv}
           AND IM.DELYN = 'N'
         WHERE UC.TABLE_NAME = #{tableName}
         GROUP BY UC.COLUMN_NAME, UC.COLUMN_ID
         ORDER BY UC.COLUMN_ID

/* oms-ordercommon-sql-oracle.xml selectCoCusttypeList */ SELECT TC.OWKEY , TC.CUSTOMERORDERKEY , TC.EXTORDERTYPECD , TC.OR_TYPE_CD , TC.WKSTATUS , TC.LOADINGYN /*배차여부*/ , TC.SPECIALOUTTYPE /*행사유형*/ , TC.SPECIALORDERTYPE /*특이주문유형(베이커리 등 구분)*/ , TC.MOVEMENT_TYPE /*이동유형*/ , TC.ORDER_ERROR_CD , TC.ORDER_ERROR_COMMENTS , DC.ACTYPE2 AS DELIVERY_KEY , SC.ACTYPE2 AS STORE_KEY , BC.ACTYPE2 AS BILLKEY , PC.ACTYPE2 AS PAYERKEY , AC.ACTYPE2 AS ACKEY
FROM ( SELECT EXTERNORDERKEY, OR_HD_DT AS HD_DT FROM TORDER_INTF_IB_HD WHERE INTERFACE_ID = #{interfaceId} AND REQUESTDT = #{requestDt} UNION ALL SELECT EXTERNORDERKEY, OR_HD_DT AS HD_DT FROM TORDER_INTF_OB_HD WHERE INTERFACE_ID = #{interfaceId} AND REQUESTDT = #{requestDt} ) TI JOIN TORDER_INFO_CO_HD TC ON TI.EXTERNORDERKEY = TC.EXTERNORDERKEY AND TI.HD_DT = TC.DELIVERY_HD_DT AND TC.INTERFACE_ID = #{interfaceId} AND TC.WKSTATUS <> #{cancelWkstatus} AND TC.OWKEY = #{owkey}
FROM (
SELECT #{item.cohdkey} AS COHDKEY /*CO번호*/
) TI JOIN TORDER_INFO_CO_HD TH ON TI.CUSTOMERORDERKEY = TH.CUSTOMERORDERKEY AND TH.WKSTATUS <> #{cancelWkstatus} AND TH.OWKEY = #{owkey}
LEFT JOIN TADMIN_MST_CUSTOMER DC ON TC.OWKEY=DC.OWKEY AND TC.DELIVERY_KEY=DC.ACKEY LEFT JOIN TADMIN_MST_CUSTOMER SC ON TC.OWKEY=SC.OWKEY AND TC.STORE_KEY=SC.ACKEY LEFT JOIN TADMIN_MST_CUSTOMER BC ON TC.OWKEY=BC.OWKEY AND TC.BILLKEY=BC.ACKEY LEFT JOIN TADMIN_MST_CUSTOMER PC ON TC.OWKEY=PC.OWKEY AND TC.PAYERKEY=PC.ACKEY LEFT JOIN TADMIN_MST_CUSTOMER AC ON TC.OWKEY=AC.OWKEY AND TC.ACKEY=AC.ACKEY

/* oms-ordercommon-sql-oracle.xml selectCoCodeRefTypeList */
SELECT LOWER(SUBSTR(REPLACE(INITCAP(COCOLUMN), '_', ''),1,1))||SUBSTR(REPLACE(INITCAP(COCOLUMN), '_', ''),2) AS COCOLUMN
     , OR_TYPE_CD
     , ISMANDATORY
     , CODE_REF_VALUE
  FROM TORDER_INFO_CO_CHK 
 WHERE OWKEY = #{owkey}
   AND HDGB = #{hdgb}
   AND CODE_REF_TYPE = #{codeRefType}
   AND DELYN = 'N'

/* oms-ordercommon-sql-oracle.xml selectInValidateCoHd */ SELECT T.* , CASE WHEN T.ERRCOL IS NULL THEN 1 ELSE 0 END AS IS_SUCCESS , CASE WHEN T.ERRCOL IS NULL THEN NULL ELSE EL.ERROR_COLUMN END AS ERROR_COLUMN , CASE WHEN T.ERRCOL IS NULL THEN NULL ELSE EL.MESSAGE_CODE END AS ERROR_CODE , CASE WHEN T.ERRCOL IS NULL THEN NULL ELSE EL.PARAM END AS ERROR_PARAM , CASE WHEN T.ERRCOL IS NULL THEN NULL ELSE REPLACE(REPLACE(COALESCE(MM.DISPLAYMSG, EL.SERVER_MESSAGE), #{param1}, COALESCE(ML.DISPLAYMSG, EL.PARAM)), #{param0}, COALESCE(ML.DISPLAYMSG, EL.PARAM)) END AS SERVER_MESSAGE FROM ( SELECT O.* , CASE WHEN O.OWKEY IS NULL AND CHK.OWKEY > 0 THEN 'OWKEY' WHEN O.COHDKEY IS NULL AND CHK.COHDKEY > 0 THEN 'COHDKEY' WHEN O.EXTORDERTYPECD IS NULL AND CHK.EXTORDERTYPECD > 0 THEN 'EXTORDERTYPECD' WHEN O.ORDERTYPECD IS NULL AND CHK.ORDERTYPECD > 0 THEN 'ORDERTYPECD' WHEN O.DLVYEXPCTDAY IS NULL AND CHK.DLVYEXPCTDAY > 0 THEN 'DLVYEXPCTDAY' WHEN O.ORDERISTDAY IS NULL AND CHK.ORDERISTDAY > 0 THEN 'ORDERISTDAY' WHEN O.WKSTATUS IS NULL AND CHK.WKSTATUS > 0 THEN 'WKSTATUS' WHEN O.DLVYACKEY IS NULL AND CHK.DLVYACKEY > 0 THEN 'DLVYACKEY' WHEN O.STOREKEY IS NULL AND CHK.STOREKEY > 0 THEN 'STOREKEY' WHEN O.BILLKEY IS NULL AND CHK.BILLKEY > 0 THEN 'BILLKEY' WHEN O.PAYERKEY IS NULL AND CHK.PAYERKEY > 0 THEN 'PAYERKEY' WHEN O.ACKEY IS NULL AND CHK.ACKEY > 0 THEN 'ACKEY' WHEN O.POTYPE IS NULL AND CHK.POTYPE > 0 THEN 'POTYPE' WHEN O.PRERFRNCDIV IS NULL AND CHK.PRERFRNCDIV > 0 THEN 'PRERFRNCDIV' WHEN O.RFRNCKEY IS NULL AND CHK.RFRNCKEY > 0 THEN 'RFRNCKEY' WHEN O.ORGORDERKEY IS NULL AND CHK.ORGORDERKEY > 0 THEN 'ORGORDERKEY' WHEN O.SALESEMPID IS NULL AND CHK.SALESEMPID > 0 THEN 'SALESEMPID' WHEN O.DLVYEMPID IS NULL AND CHK.DLVYEMPID > 0 THEN 'DLVYEMPID' WHEN O.CMT IS NULL AND CHK.CMT > 0 THEN 'CMT' WHEN O.ADDCMT01 IS NULL AND CHK.ADDCMT01 > 0 THEN 'ADDCMT01' WHEN O.ADDCMT02 IS NULL AND CHK.ADDCMT01 > 0 THEN 'ADDCMT02' WHEN O.CNLYN IS NULL AND CHK.CNLYN > 0 THEN 'CNLYN' WHEN O.CNLID IS NULL AND CHK.CNLID > 0 THEN 'CNLID' WHEN O.ORDERERRCD IS NULL AND CHK.ORDERERRCD > 0 THEN 'ORDERERRCD' WHEN O.ORDERERRCMT IS NULL AND CHK.ORDERERRCMT > 0 THEN 'ORDERERRCMT' WHEN O.EDIYN IS NULL AND CHK.EDIYN > 0 THEN 'EDIYN' WHEN O.FROMTOCTKEY IS NULL AND CHK.FROMTOCTKEY > 0 THEN 'FROMTOCTKEY' WHEN O.CTKEY IS NULL AND CHK.CTKEY > 0 THEN 'CTKEY' WHEN O.ERPSNDFAILYN IS NULL AND CHK.ERPSNDFAILYN > 0 THEN 'ERPSNDFAILYN' WHEN O.ERPSNDSEQ IS NULL AND CHK.ERPSNDSEQ > 0 THEN 'ERPSNDSEQ' WHEN O.SPLITORDERYN IS NULL AND CHK.SPLITORDERYN > 0 THEN 'SPLITORDERYN' WHEN O.ERPRESPONSECD IS NULL AND CHK.ERPRESPONSECD > 0 THEN 'ERPRESPONSECD' WHEN O.FAILCNT IS NULL AND CHK.FAILCNT > 0 THEN 'FAILCNT' WHEN O.RECPNM IS NULL AND CHK.RECPNM > 0 THEN 'RECPNM' WHEN O.RECPADDRHD IS NULL AND CHK.RECPADDRHD > 0 THEN 'RECPADDRHD' WHEN O.RECPADDRDT IS NULL AND CHK.RECPADDRDT > 0 THEN 'RECPADDRDT' WHEN O.RECPZIPCD IS NULL AND CHK.RECPZIPCD > 0 THEN 'RECPZIPCD' WHEN O.RECPTEL01 IS NULL AND CHK.RECPTEL01 > 0 THEN 'RECPTEL01' WHEN O.RECPTEL02 IS NULL AND CHK.RECPTEL02 > 0 THEN 'RECPTEL02' WHEN O.BUYER IS NULL AND CHK.BUYER > 0 THEN 'BUYER' WHEN O.BUYERADDRHD IS NULL AND CHK.BUYERADDRHD > 0 THEN 'BUYERADDRHD' WHEN O.BUYERADDRDT IS NULL AND CHK.BUYERADDRDT > 0 THEN 'BUYERADDRDT' WHEN O.BUYERZIPCD IS NULL AND CHK.BUYERZIPCD > 0 THEN 'BUYERZIPCD' WHEN O.BUYERTEL01 IS NULL AND CHK.BUYERTEL01 > 0 THEN 'BUYERTEL01' WHEN O.BUYERTEL02 IS NULL AND CHK.BUYERTEL02 > 0 THEN 'BUYERTEL02' WHEN O.RECALLER IS NULL AND CHK.RECALLER > 0 THEN 'RECALLER' WHEN O.RECALLERADDRHD IS NULL AND CHK.RECALLERADDRHD > 0 THEN 'RECALLERADDRHD' WHEN O.RECALLERADDRDT IS NULL AND CHK.RECALLERADDRDT > 0 THEN 'RECALLERADDRDT' WHEN O.RECALLERZIPCD IS NULL AND CHK.RECALLERZIPCD > 0 THEN 'RECALLERZIPCD' WHEN O.RECALLERTEL01 IS NULL AND CHK.RECALLERTEL01 > 0 THEN 'RECALLERTEL01' WHEN O.RECALLERTEL02 IS NULL AND CHK.RECALLERTEL02 > 0 THEN 'RECALLERTEL02' WHEN O.RIRSNCD IS NULL AND CHK.RIRSNCD > 0 THEN 'RIRSNCD' WHEN O.CLAIMNO IS NULL AND CHK.CLAIMNO > 0 THEN 'CLAIMNO' WHEN O.DLVYMETHDCD IS NULL AND CHK.DLVYMETHDCD > 0 THEN 'DLVYMETHDCD' WHEN O.DLVYMETHDDTCD IS NULL AND CHK.DLVYMETHDDTCD > 0 THEN 'DLVYMETHDDTCD' WHEN O.MALORDERDIV IS NULL AND CHK.MALORDERDIV > 0 THEN 'MALORDERDIV' WHEN O.NISYN IS NULL AND CHK.NISYN > 0 THEN 'NISYN' WHEN O.NISCNLRNGDIV IS NULL AND CHK.NISCNLRNGDIV > 0 THEN 'NISCNLRNGDIV' WHEN O.PAYMTCOMPLDAY IS NULL AND CHK.PAYMTCOMPLDAY > 0 THEN 'PAYMTCOMPLDAY' WHEN O.PARTERID IS NULL AND CHK.PARTERID > 0 THEN 'PARTERID' WHEN O.ACCESSKEY IS NULL AND CHK.ACCESSKEY > 0 THEN 'ACCESSKEY' WHEN O.SHMISTNO IS NULL AND CHK.SHMISTNO > 0 THEN 'SHMISTNO' WHEN O.REQORDERNO IS NULL AND CHK.REQORDERNO > 0 THEN 'REQORDERNO' WHEN CHK.FROMTOCTKEY > 0 AND TCT.CTKEY IS NULL THEN 'FROMTOCTKEY_M' WHEN CHK.CTKEY > 0 AND CT.CTKEY IS NULL THEN 'CTKEY_M' WHEN OM.ORDERTYPECD IS NULL THEN 'ORTYPEMAPP_M' ELSE NULL END AS ERRCOL FROM (
SELECT TH.* FROM ( SELECT REQORDERNO, CLAIMNO-- DLVYEXPCTDAY FROM TORDER_INTF_IBORDER_HD WHERE IFID = #{interfaceId} AND REQUESTDT = #{requestDt} ) TI JOIN TORDER_INFO_CO_HD TH ON (TI.REQORDERNO = TH.REQORDERNO OR TI.CLAIMNO = TH.CLAIMNO) --AND TI.DLVYEXPCTDAY = TH.DLVYEXPCTDAY AND TH.IFID = #{interfaceId} AND TH.WKSTATUS NOT IN ( #{cancelWkstatus}, #{failWkstatus}) AND TH.OWKEY = #{owkey}
SELECT #{item.owkey} AS OWKEY /*화주코드*/ , #{item.cohdkey} AS COHDKEY /*고객주문번호*/ , #{item.extordertypecd} AS EXTORDERTYPECD /*화주오더유형*/ , #{item.ordertypecd} AS ORDERTYPECD /*시스템오더유형*/ , #{item.dlvyexpctday} AS DLVYEXPCTDAY /*배송예정일자*/ , #{item.orderistday} AS ORDERISTDAY /*지시일자*/ , #{item.wkstatus} AS WKSTATUS /*작업(주문) 상태*/ , #{item.dlvyackey} AS DLVYACKEY /*납품처코드*/ , #{item.storekey} AS STOREKEY /*판매처코드*/ , #{item.billkey} AS BILLKEY /*정산처코드*/ , #{item.payerkey} AS PAYERKEY /*청구처코드*/ , #{item.ackey} AS ACKEY /*공급처코드*/ , #{item.potype} AS POTYPE /*PO타입*/ , #{item.prerfrncdiv} AS PRERFRNCDIV /*이전참조구분*/ , #{item.rfrnckey} AS RFRNCKEY /*이전참조문서번호*/ , #{item.orgorderkey} AS ORGORDERKEY /*외부주문번호*/ , #{item.salesempid} AS SALESEMPID /*영업사원ID*/ , #{item.dlvyempid} AS DLVYEMPID /*배송사원ID*/ , #{item.cmt} AS CMT /*비고*/ , #{item.addcmt01} AS ADDCMT01 /*추가비고*/ , #{item.addcmt02} AS ADDCMT02 /*추가비고*/ , #{item.cnlyn} AS CNLYN /*주문취소여부*/ , #{item.cnlid} AS CNLID /*주문취소ID*/
, #{item.ordererrcd} AS ORDERERRCD /*주문오류 코드*/ , #{item.ordererrcmt} AS ORDERERRCMT /*주문생성 오류비고*/ , #{item.ediyn} AS EDIYN /*EDI 등록 여부*/ , #{item.fromtoctkey} AS FROMTOCTKEY /*TO_센터*/ , #{item.ctkey} AS CTKEY /*작업센터*/ , #{item.erpsndfailyn} AS ERPSNDFAILYN , #{item.erpsndseq} AS ERPSNDSEQ , #{item.splitorderyn} AS SPLITORDERYN , #{item.erpresponsecd} AS ERPRESPONSECD , #{item.failcnt} AS FAILCNT , #{item.recpnm} AS RECPNM , #{item.recpaddrhd} AS RECPADDRHD , #{item.recpaddrdt} AS RECPADDRDT , #{item.recpzipcd} AS RECPZIPCD , #{item.recptel01} AS RECPTEL01 , #{item.recptel02} AS RECPTEL02 , #{item.buyer} AS BUYER , #{item.buyeraddrhd} AS BUYERADDRHD , #{item.buyeraddrdt} AS BUYERADDRDT , #{item.buyerzipcd} AS BUYERZIPCD , #{item.buyertel01} AS BUYERTEL01 , #{item.buyertel02} AS BUYERTEL02 , #{item.recaller} AS RECALLER , #{item.recalleraddrhd} AS RECALLERADDRHD , #{item.recalleraddrdt} AS RECALLERADDRDT , #{item.recallerzipcd} AS RECALLERZIPCD , #{item.recallertel01} AS RECALLERTEL01 , #{item.recallertel02} AS RECALLERTEL02 , #{item.rirsncd} AS RIRSNCD , #{item.claimno} AS CLAIMNO , #{item.dlvymethdcd} AS DLVYMETHDCD , #{item.dlvymethddtcd} AS DLVYMETHDDTCD , #{item.malorderdiv} AS MALORDERDIV , #{item.nisyn} AS NISYN , #{item.niscnlrngdiv} AS NISCNLRNGDIV , #{item.paymtcomplday} AS PAYMTCOMPLDAY , #{item.parterid} AS PARTERID , #{item.accesskey} AS ACCESSKEY , #{item.shmistno} AS SHMISTNO , #{item.reqorderno} AS REQORDERNO , #{item.uploadkey} AS UPLOADKEY , #{item.insertdate} AS INSERTDATE /*입력 일시*/ , #{item.inserturkey} AS INSERTURKEY /*입력 사용자 ID*/ , #{item.updatedate} AS UPDATEDATE /*수정 일시*/ , #{item.updateurkey} AS UPDATEURKEY /*수정 사용자 ID*/
SELECT TH.* FROM (
SELECT #{item.cohdkey} AS COHDKEY /*CO번호*/
) TI JOIN TORDER_INFO_CO_HD TH ON TI.COHDKEY = TH.COHDKEY AND TH.WKSTATUS NOT IN ( #{cancelWkstatus}, #{failWkstatus}) AND TH.OWKEY = #{owkey}
) O LEFT JOIN ( SELECT OWKEY , ORDERTYPECD , SUM(CASE WHEN COCOLUMN='EXTORDERTYPECD' THEN 1 ELSE 0 END) AS EXTORDERTYPECD , SUM(CASE WHEN COCOLUMN='COHDKEY' THEN 1 ELSE 0 END) AS COHDKEY , SUM(CASE WHEN COCOLUMN='DLVYEXPCTDAY' THEN 1 ELSE 0 END) AS DLVYEXPCTDAY , SUM(CASE WHEN COCOLUMN='ORDERISTDAY' THEN 1 ELSE 0 END) AS ORDERISTDAY , SUM(CASE WHEN COCOLUMN='WKSTATUS' THEN 1 ELSE 0 END) AS WKSTATUS , SUM(CASE WHEN COCOLUMN='DLVYACKEY' THEN 1 ELSE 0 END) AS DLVYACKEY , SUM(CASE WHEN COCOLUMN='STOREKEY' THEN 1 ELSE 0 END) AS STOREKEY , SUM(CASE WHEN COCOLUMN='BILLKEY' THEN 1 ELSE 0 END) AS BILLKEY , SUM(CASE WHEN COCOLUMN='PAYERKEY' THEN 1 ELSE 0 END) AS PAYERKEY , SUM(CASE WHEN COCOLUMN='ACKEY' THEN 1 ELSE 0 END) AS ACKEY , SUM(CASE WHEN COCOLUMN='POTYPE' THEN 1 ELSE 0 END) AS POTYPE , SUM(CASE WHEN COCOLUMN='PRERFRNCDIV' THEN 1 ELSE 0 END) AS PRERFRNCDIV , SUM(CASE WHEN COCOLUMN='RFRNCKEY' THEN 1 ELSE 0 END) AS RFRNCKEY , SUM(CASE WHEN COCOLUMN='ORGORDERKEY' THEN 1 ELSE 0 END) AS ORGORDERKEY , SUM(CASE WHEN COCOLUMN='SALESEMPID' THEN 1 ELSE 0 END) AS SALESEMPID , SUM(CASE WHEN COCOLUMN='DLVYEMPID' THEN 1 ELSE 0 END) AS DLVYEMPID , SUM(CASE WHEN COCOLUMN='CMT' THEN 1 ELSE 0 END) AS CMT , SUM(CASE WHEN COCOLUMN='ADDCMT01' THEN 1 ELSE 0 END) AS ADDCMT01 , SUM(CASE WHEN COCOLUMN='ADDCMT02' THEN 1 ELSE 0 END) AS ADDCMT02 , SUM(CASE WHEN COCOLUMN='CNLYN' THEN 1 ELSE 0 END) AS CNLYN , SUM(CASE WHEN COCOLUMN='CNLID' THEN 1 ELSE 0 END) AS CNLID , SUM(CASE WHEN COCOLUMN='ORDERERRCD' THEN 1 ELSE 0 END) AS ORDERERRCD , SUM(CASE WHEN COCOLUMN='ORDERERRCMT' THEN 1 ELSE 0 END) AS ORDERERRCMT , SUM(CASE WHEN COCOLUMN='EDIYN' THEN 1 ELSE 0 END) AS EDIYN , SUM(CASE WHEN COCOLUMN='FROMTOCTKEY' THEN 1 ELSE 0 END) AS FROMTOCTKEY , SUM(CASE WHEN COCOLUMN='CTKEY' THEN 1 ELSE 0 END) AS CTKEY , SUM(CASE WHEN COCOLUMN='ERPSNDFAILYN' THEN 1 ELSE 0 END) AS ERPSNDFAILYN , SUM(CASE WHEN COCOLUMN='ERPSNDSEQ' THEN 1 ELSE 0 END) AS ERPSNDSEQ , SUM(CASE WHEN COCOLUMN='SPLITORDERYN' THEN 1 ELSE 0 END) AS SPLITORDERYN , SUM(CASE WHEN COCOLUMN='ERPRESPONSECD' THEN 1 ELSE 0 END) AS ERPRESPONSECD , SUM(CASE WHEN COCOLUMN='FAILCNT' THEN 1 ELSE 0 END) AS FAILCNT , SUM(CASE WHEN COCOLUMN='RECPNM' THEN 1 ELSE 0 END) AS RECPNM , SUM(CASE WHEN COCOLUMN='RECPADDRHD' THEN 1 ELSE 0 END) AS RECPADDRHD , SUM(CASE WHEN COCOLUMN='RECPADDRDT' THEN 1 ELSE 0 END) AS RECPADDRDT , SUM(CASE WHEN COCOLUMN='RECPZIPCD' THEN 1 ELSE 0 END) AS RECPZIPCD , SUM(CASE WHEN COCOLUMN='RECPTEL01' THEN 1 ELSE 0 END) AS RECPTEL01 , SUM(CASE WHEN COCOLUMN='RECPTEL02' THEN 1 ELSE 0 END) AS RECPTEL02 , SUM(CASE WHEN COCOLUMN='BUYER' THEN 1 ELSE 0 END) AS BUYER , SUM(CASE WHEN COCOLUMN='BUYERADDRHD' THEN 1 ELSE 0 END) AS BUYERADDRHD , SUM(CASE WHEN COCOLUMN='BUYERADDRDT' THEN 1 ELSE 0 END) AS BUYERADDRDT , SUM(CASE WHEN COCOLUMN='BUYERZIPCD' THEN 1 ELSE 0 END) AS BUYERZIPCD , SUM(CASE WHEN COCOLUMN='BUYERTEL01' THEN 1 ELSE 0 END) AS BUYERTEL01 , SUM(CASE WHEN COCOLUMN='BUYERTEL02' THEN 1 ELSE 0 END) AS BUYERTEL02 , SUM(CASE WHEN COCOLUMN='RECALLER' THEN 1 ELSE 0 END) AS RECALLER , SUM(CASE WHEN COCOLUMN='RECALLERADDRHD' THEN 1 ELSE 0 END) AS RECALLERADDRHD , SUM(CASE WHEN COCOLUMN='RECALLERADDRDT' THEN 1 ELSE 0 END) AS RECALLERADDRDT , SUM(CASE WHEN COCOLUMN='RECALLERZIPCD' THEN 1 ELSE 0 END) AS RECALLERZIPCD , SUM(CASE WHEN COCOLUMN='RECALLERTEL01' THEN 1 ELSE 0 END) AS RECALLERTEL01 , SUM(CASE WHEN COCOLUMN='RECALLERTEL02' THEN 1 ELSE 0 END) AS RECALLERTEL02 , SUM(CASE WHEN COCOLUMN='RIRSNCD' THEN 1 ELSE 0 END) AS RIRSNCD , SUM(CASE WHEN COCOLUMN='CLAIMNO' THEN 1 ELSE 0 END) AS CLAIMNO , SUM(CASE WHEN COCOLUMN='DLVYMETHDCD' THEN 1 ELSE 0 END) AS DLVYMETHDCD , SUM(CASE WHEN COCOLUMN='DLVYMETHDDTCD' THEN 1 ELSE 0 END) AS DLVYMETHDDTCD , SUM(CASE WHEN COCOLUMN='MALORDERDIV' THEN 1 ELSE 0 END) AS MALORDERDIV , SUM(CASE WHEN COCOLUMN='NISYN' THEN 1 ELSE 0 END) AS NISYN , SUM(CASE WHEN COCOLUMN='NISCNLRNGDIV' THEN 1 ELSE 0 END) AS NISCNLRNGDIV , SUM(CASE WHEN COCOLUMN='PAYMTCOMPLDAY' THEN 1 ELSE 0 END) AS PAYMTCOMPLDAY , SUM(CASE WHEN COCOLUMN='PARTERID' THEN 1 ELSE 0 END) AS PARTERID , SUM(CASE WHEN COCOLUMN='ACCESSKEY' THEN 1 ELSE 0 END) AS ACCESSKEY , SUM(CASE WHEN COCOLUMN='SHMISTNO' THEN 1 ELSE 0 END) AS SHMISTNO , SUM(CASE WHEN COCOLUMN='REQORDERNO' THEN 1 ELSE 0 END) AS REQORDERNO FROM TORDER_INFO_CO_CHK WHERE OWKEY = #{owkey} AND HDDTDIV = #{hddtdiv} AND DELYN = 'N' AND REQRDYN = 'Y' GROUP BY OWKEY, ORDERTYPECD ) CHK ON O.OWKEY = CHK.OWKEY AND O.ORDERTYPECD = CHK.ORDERTYPECD LEFT JOIN TORDER_MST_CT CT ON O.CTKEY = CT.CTKEY LEFT JOIN TORDER_MST_CT TCT ON O.FROMTOCTKEY = TCT.CTKEY LEFT JOIN TORDER_INFO_ORTYPE_MAPPING OM ON O.OWKEY = OM.OWKEY AND O.EXTORDERTYPECD = OM.EXTORDERTYPECD AND O.ORDERTYPECD = OM.ORDERTYPECD AND OM.DELYN='N' ) T LEFT JOIN (
) EL ON T.ERRCOL = EL.COCOLUMN LEFT JOIN TADMIN_MST_MULAAPMSG_DT ML ON EL.PARAM = ML.MULAAPMSGHDKEY AND ML.LAKEY = COALESCE(#{lakey}, 'KOR') LEFT JOIN TADMIN_MST_MULAAPMSG_DT MM ON 'MSG_' || EL.MESSAGE_CODE = MM.MULAAPMSGHDKEY AND MM.LAKEY = COALESCE(#{lakey}, 'KOR') WHERE 1=1

/* oms-ordercommon-sql-oracle.xml selectOutValidateCoHd */ SELECT T.* , CASE WHEN T.ERRCOL IS NULL THEN 1 ELSE 0 END AS IS_SUCCESS , CASE WHEN T.ERRCOL IS NULL THEN NULL ELSE EL.ERROR_COLUMN END AS ERROR_COLUMN , CASE WHEN T.ERRCOL IS NULL THEN NULL ELSE EL.MESSAGE_CODE END AS ERROR_CODE , CASE WHEN T.ERRCOL IS NULL THEN NULL ELSE EL.PARAM END AS ERROR_PARAM , CASE WHEN T.ERRCOL IS NULL THEN NULL ELSE REPLACE(REPLACE(COALESCE(MM.DISPLAYMSG, EL.SERVER_MESSAGE), #{param1}, COALESCE(ML.DISPLAYMSG, EL.PARAM)), #{param0}, COALESCE(ML.DISPLAYMSG, EL.PARAM)) END AS SERVER_MESSAGE FROM ( SELECT O.* , CASE WHEN O.OWKEY IS NULL AND CHK.OWKEY > 0 THEN 'OWKEY' WHEN O.COHDKEY IS NULL AND CHK.COHDKEY > 0 THEN 'COHDKEY' WHEN O.EXTORDERTYPECD IS NULL AND CHK.EXTORDERTYPECD > 0 THEN 'EXTORDERTYPECD' WHEN O.ORDERTYPECD IS NULL AND CHK.ORDERTYPECD > 0 THEN 'ORDERTYPECD' WHEN O.DLVYEXPCTDAY IS NULL AND CHK.DLVYEXPCTDAY > 0 THEN 'DLVYEXPCTDAY' WHEN O.ORDERISTDAY IS NULL AND CHK.ORDERISTDAY > 0 THEN 'ORDERISTDAY' WHEN O.WKSTATUS IS NULL AND CHK.WKSTATUS > 0 THEN 'WKSTATUS' WHEN O.DLVYACKEY IS NULL AND CHK.DLVYACKEY > 0 THEN 'DLVYACKEY' WHEN O.STOREKEY IS NULL AND CHK.STOREKEY > 0 THEN 'STOREKEY' WHEN O.BILLKEY IS NULL AND CHK.BILLKEY > 0 THEN 'BILLKEY' WHEN O.PAYERKEY IS NULL AND CHK.PAYERKEY > 0 THEN 'PAYERKEY' WHEN O.ACKEY IS NULL AND CHK.ACKEY > 0 THEN 'ACKEY' WHEN O.POTYPE IS NULL AND CHK.POTYPE > 0 THEN 'POTYPE' WHEN O.PRERFRNCDIV IS NULL AND CHK.PRERFRNCDIV > 0 THEN 'PRERFRNCDIV' WHEN O.RFRNCKEY IS NULL AND CHK.RFRNCKEY > 0 THEN 'RFRNCKEY' WHEN O.ORGORDERKEY IS NULL AND CHK.ORGORDERKEY > 0 THEN 'ORGORDERKEY' WHEN O.SALESEMPID IS NULL AND CHK.SALESEMPID > 0 THEN 'SALESEMPID' WHEN O.DLVYEMPID IS NULL AND CHK.DLVYEMPID > 0 THEN 'DLVYEMPID' WHEN O.CMT IS NULL AND CHK.CMT > 0 THEN 'CMT' WHEN O.ADDCMT01 IS NULL AND CHK.ADDCMT01 > 0 THEN 'ADDCMT01' WHEN O.ADDCMT02 IS NULL AND CHK.ADDCMT01 > 0 THEN 'ADDCMT02' WHEN O.CNLYN IS NULL AND CHK.CNLYN > 0 THEN 'CNLYN' WHEN O.CNLID IS NULL AND CHK.CNLID > 0 THEN 'CNLID' WHEN O.ORDERERRCD IS NULL AND CHK.ORDERERRCD > 0 THEN 'ORDERERRCD' WHEN O.ORDERERRCMT IS NULL AND CHK.ORDERERRCMT > 0 THEN 'ORDERERRCMT' WHEN O.EDIYN IS NULL AND CHK.EDIYN > 0 THEN 'EDIYN' WHEN O.FROMTOCTKEY IS NULL AND CHK.FROMTOCTKEY > 0 THEN 'FROMTOCTKEY' WHEN O.CTKEY IS NULL AND CHK.CTKEY > 0 THEN 'CTKEY' WHEN O.ERPSNDFAILYN IS NULL AND CHK.ERPSNDFAILYN > 0 THEN 'ERPSNDFAILYN' WHEN O.ERPSNDSEQ IS NULL AND CHK.ERPSNDSEQ > 0 THEN 'ERPSNDSEQ' WHEN O.SPLITORDERYN IS NULL AND CHK.SPLITORDERYN > 0 THEN 'SPLITORDERYN' WHEN O.ERPRESPONSECD IS NULL AND CHK.ERPRESPONSECD > 0 THEN 'ERPRESPONSECD' WHEN O.FAILCNT IS NULL AND CHK.FAILCNT > 0 THEN 'FAILCNT' WHEN O.RECPNM IS NULL AND CHK.RECPNM > 0 THEN 'RECPNM' WHEN O.RECPADDRHD IS NULL AND CHK.RECPADDRHD > 0 THEN 'RECPADDRHD' WHEN O.RECPADDRDT IS NULL AND CHK.RECPADDRDT > 0 THEN 'RECPADDRDT' WHEN O.RECPZIPCD IS NULL AND CHK.RECPZIPCD > 0 THEN 'RECPZIPCD' WHEN O.RECPTEL01 IS NULL AND CHK.RECPTEL01 > 0 THEN 'RECPTEL01' WHEN O.RECPTEL02 IS NULL AND CHK.RECPTEL02 > 0 THEN 'RECPTEL02' WHEN O.BUYER IS NULL AND CHK.BUYER > 0 THEN 'BUYER' WHEN O.BUYERADDRHD IS NULL AND CHK.BUYERADDRHD > 0 THEN 'BUYERADDRHD' WHEN O.BUYERADDRDT IS NULL AND CHK.BUYERADDRDT > 0 THEN 'BUYERADDRDT' WHEN O.BUYERZIPCD IS NULL AND CHK.BUYERZIPCD > 0 THEN 'BUYERZIPCD' WHEN O.BUYERTEL01 IS NULL AND CHK.BUYERTEL01 > 0 THEN 'BUYERTEL01' WHEN O.BUYERTEL02 IS NULL AND CHK.BUYERTEL02 > 0 THEN 'BUYERTEL02' WHEN O.RECALLER IS NULL AND CHK.RECALLER > 0 THEN 'RECALLER' WHEN O.RECALLERADDRHD IS NULL AND CHK.RECALLERADDRHD > 0 THEN 'RECALLERADDRHD' WHEN O.RECALLERADDRDT IS NULL AND CHK.RECALLERADDRDT > 0 THEN 'RECALLERADDRDT' WHEN O.RECALLERZIPCD IS NULL AND CHK.RECALLERZIPCD > 0 THEN 'RECALLERZIPCD' WHEN O.RECALLERTEL01 IS NULL AND CHK.RECALLERTEL01 > 0 THEN 'RECALLERTEL01' WHEN O.RECALLERTEL02 IS NULL AND CHK.RECALLERTEL02 > 0 THEN 'RECALLERTEL02' WHEN O.RIRSNCD IS NULL AND CHK.RIRSNCD > 0 THEN 'RIRSNCD' WHEN O.CLAIMNO IS NULL AND CHK.CLAIMNO > 0 