SELECT TD.* , TH.ORDERTYPECD , TH.CTKEY FROM (
SELECT #{item.cohdkey} AS COHDKEY /*CO번호*/
) TI JOIN TORDER_INFO_CO_HD TH ON TI.COHDKEY = TH.COHDKEY AND TH.WKSTATUS NOT IN ( #{cancelWkstatus}, #{failWkstatus}) AND TH.OWKEY = #{owkey} JOIN TORDER_INFO_CO_DT TD ON TH.OWKEY = TD.OWKEY AND TH.COHDKEY = TD.COHDKEY
) O LEFT JOIN ( SELECT OWKEY , ORDERTYPECD , SUM(CASE WHEN COCOLUMN='COHDKEY' THEN 1 ELSE 0 END) AS COHDKEY , SUM(CASE WHEN COCOLUMN='CODTKEY' THEN 1 ELSE 0 END) AS CODTKEY , SUM(CASE WHEN COCOLUMN='EXTORDERTYPECD' THEN 1 ELSE 0 END) AS EXTORDERTYPECD , SUM(CASE WHEN COCOLUMN='WKSTATUS' THEN 1 ELSE 0 END) AS WKSTATUS , SUM(CASE WHEN COCOLUMN='ICKEY' THEN 1 ELSE 0 END) AS ICKEY , SUM(CASE WHEN COCOLUMN='ORDERISTDAY' THEN 1 ELSE 0 END) AS ORDERISTDAY , SUM(CASE WHEN COCOLUMN='DLVYEXPCTDAY' THEN 1 ELSE 0 END) AS DLVYEXPCTDAY , SUM(CASE WHEN COCOLUMN='ORDERISTQTY' THEN 1 ELSE 0 END) AS ORDERISTQTY , SUM(CASE WHEN COCOLUMN='UNIT' THEN 1 ELSE 0 END) AS UNIT , SUM(CASE WHEN COCOLUMN='CNVRTQTY' THEN 1 ELSE 0 END) AS CNVRTQTY , SUM(CASE WHEN COCOLUMN='PRDCTLOT' THEN 1 ELSE 0 END) AS PRDCTLOT , SUM(CASE WHEN COCOLUMN='PRDCTDAY' THEN 1 ELSE 0 END) AS PRDCTDAY , SUM(CASE WHEN COCOLUMN='TTWEIGHT' THEN 1 ELSE 0 END) AS TTWEIGHT , SUM(CASE WHEN COCOLUMN='WEIGHTUNIT' THEN 1 ELSE 0 END) AS WEIGHTUNIT , SUM(CASE WHEN COCOLUMN='VOL' THEN 1 ELSE 0 END) AS VOL , SUM(CASE WHEN COCOLUMN='VOLUNIT' THEN 1 ELSE 0 END) AS VOLUNIT , SUM(CASE WHEN COCOLUMN='LOGGRPCD' THEN 1 ELSE 0 END) AS LOGGRPCD , SUM(CASE WHEN COCOLUMN='ORGORDERKEY' THEN 1 ELSE 0 END) AS ORGORDERKEY , SUM(CASE WHEN COCOLUMN='ORGORDERDTKEY' THEN 1 ELSE 0 END) AS ORGORDERDTKEY , SUM(CASE WHEN COCOLUMN='CMT' THEN 1 ELSE 0 END) AS CMT , SUM(CASE WHEN COCOLUMN='CNLYN' THEN 1 ELSE 0 END) AS CNLYN , SUM(CASE WHEN COCOLUMN='CNLID' THEN 1 ELSE 0 END) AS CNLID , SUM(CASE WHEN COCOLUMN='PRERFRNCDIV' THEN 1 ELSE 0 END) AS PRERFRNCDIV , SUM(CASE WHEN COCOLUMN='RFRNCKEY' THEN 1 ELSE 0 END) AS RFRNCKEY , SUM(CASE WHEN COCOLUMN='RFRNCDTKEY' THEN 1 ELSE 0 END) AS RFRNCDTKEY , SUM(CASE WHEN COCOLUMN='ORDERERRCD' THEN 1 ELSE 0 END) AS ORDERERRCD , SUM(CASE WHEN COCOLUMN='ORDERERRCMT' THEN 1 ELSE 0 END) AS ORDERERRCMT , SUM(CASE WHEN COCOLUMN='DLVYCNTRUNIT' THEN 1 ELSE 0 END) AS DLVYCNTRUNIT , SUM(CASE WHEN COCOLUMN='MALBOXQTY' THEN 1 ELSE 0 END) AS MALBOXQTY , SUM(CASE WHEN COCOLUMN='MALPCSQTY' THEN 1 ELSE 0 END) AS MALPCSQTY , SUM(CASE WHEN COCOLUMN='REQORDERNO' THEN 1 ELSE 0 END) AS REQORDERNO FROM TORDER_INFO_CO_CHK WHERE OWKEY = #{owkey} AND HDDTDIV = #{hddtdiv} AND DELYN = 'N' AND REQRDYN = 'Y' GROUP BY OWKEY, ORDERTYPECD ) CHK ON O.OWKEY = CHK.OWKEY AND O.ORDERTYPECD = CHK.ORDERTYPECD LEFT JOIN TORDER_MST_ORTYPE OT ON O.OWKEY = OT.OWKEY AND O.ORDERTYPECD = OT.ORDERTYPECD LEFT JOIN TORDER_MST_IC IC ON O.OWKEY = IC.OWKEY AND O.ICKEY = IC.ICKEY AND IC.DELYN = 'N' LEFT JOIN TORDER_MST_ICUTXTYPE IU ON IC.OWKEY = IU.OWKEY AND IC.ICKEY = IU.ICKEY AND O.UNIT = IU.ICUNITTYPE ) T LEFT JOIN (
) EL ON T.ERRCOL = EL.COCOLUMN LEFT JOIN TADMIN_MST_MULAAPMSG_DT ML ON EL.PARAM = ML.MULAAPMSGHDKEY AND ML.LAKEY = COALESCE(#{lakey}, 'KOR') LEFT JOIN TADMIN_MST_MULAAPMSG_DT MM ON 'MSG_' || EL.MESSAGE_CODE = MM.MULAAPMSGHDKEY AND MM.LAKEY = COALESCE(#{lakey}, 'KOR') WHERE 1=1

/* oms-ordercommon-sql-oracle.xml selectCoDuplicateList_bak */
SELECT TT.OWKEY
     , TT.EXTERNORDERKEY
     , TT.CUSTOMERORDERKEY
     , #{errorCode} AS ORDER_ERROR_CD
     , COALESCE(MAX(MM.DISPLAYMSG), #{errorMessage}) AS ORDER_ERROR_COMMENTS
  FROM (
        SELECT CH.EXTERNORDERKEY
             , CH.CUSTOMERORDERKEY
             , CD.CUSTOMERORDERDTKEY
             , CD.OWKEY
             , CH.INTERFACE_ID
             , COUNT(1) OVER(PARTITION BY CD.EXTERNORDERKEY, CD.EXTERNORDERDETAILKEY) AS CNT

	  	  FROM (
                SELECT EXTERNORDERKEY, EXTERNORDERDETAILKEY
                  FROM TORDER_INTF_IB_DT
                 WHERE INTERFACE_ID = #{interfaceId}
	 	  		   AND REQUESTDT = #{requestDt}        
                UNION ALL
                SELECT EXTERNORDERKEY, EXTERNORDERDETAILKEY
                  FROM TORDER_INTF_OB_DT
                 WHERE INTERFACE_ID = #{interfaceId}
	 	  		   AND REQUESTDT = #{requestDt}        
               ) TI
          JOIN TORDER_INFO_CO_DT CD
            ON TI.EXTERNORDERKEY = CD.EXTERNORDERKEY
           AND TI.EXTERNORDERDETAILKEY = CD.EXTERNORDERDETAILKEY
           AND CD.OWKEY = #{owkey}
          JOIN TORDER_INFO_CO_HD CH
            ON CD.OWKEY = CH.OWKEY
           AND CD.CUSTOMERORDERKEY = CH.CUSTOMERORDERKEY
           AND CD.WKSTATUS <> #{cancelWkstatus}


		  FROM (

		        SELECT #{item.cohdkey} AS COHDKEY    /*CO번호*/

		       ) TI
		  JOIN TORDER_INFO_CO_HD CH
            ON CH.OWKEY = #{owkey}
           AND TI.CUSTOMERORDERKEY = CH.CUSTOMERORDERKEY
           AND CH.WKSTATUS <> #{cancelWkstatus}
          JOIN TORDER_INFO_CO_DT CD
            ON CH.OWKEY = CD.OWKEY
           AND CH.CUSTOMERORDERKEY = CD.CUSTOMERORDERKEY
           AND CD.WKSTATUS <> #{cancelWkstatus}

       ) TT		
  LEFT JOIN TADMIN_MST_MULAAPMSG_DT MM
    ON MM.MULAAPMSGHDKEY = 'MSG_' || #{errorCode}
   AND MM.LAKEY = COALESCE(#{lakey}, 'KOR')   		      
 WHERE TT.CNT > 1
   AND TT.INTERFACE_ID = #{interfaceId}
 GROUP BY TT.OWKEY, TT.EXTERNORDERKEY, TT.CUSTOMERORDERKEY

/* oms-ordercommon-sql-oracle.xml selectCoMultiDuplicateList */ SELECT TT.OWKEY , TT.ORGORDERKEY , #{errorCode} AS ORDER_ERROR_CD , COALESCE(MAX(MM.DISPLAYMSG), #{errorMessage}) AS ORDER_ERROR_COMMENTS FROM ( SELECT TI.ORGORDERKEY , TI.ORGORDERDTKEY , TI.OWKEY , COUNT(1) AS CNT FROM (
SELECT #{item.orgorderkey} AS ORGORDERKEY , #{item.orgorderdtkey} AS ORGORDERDTKEY , #{item.owkey} AS OWKEY
) TI GROUP BY TI.ORGORDERKEY , TI.ORGORDERDTKEY , TI.OWKEY HAVING COUNT(1) > 1 UNION ALL SELECT CD.ORGORDERKEY , CD.ORGORDERDTKEY , CD.OWKEY , COUNT(1) OVER(PARTITION BY CD.ORGORDERKEY, CD.EXTERNORDERDETAILKEY) AS CNT FROM (
SELECT #{item.orgorderkey} AS ORGORDERKEY , #{item.orgorderdtkey} AS ORGORDERDTKEY , #{item.owkey} AS OWKEY
) TI JOIN TORDER_INFO_CO_DT CD ON TI.OWKEY = CD.OWKEY AND TI.ORGORDERKEY = CD.ORGORDERKEY AND TI.ORGORDERDTKEY = CD.ORGORDERDTKEY AND CD.ORGORDERKEY IS NOT NULL AND CD.ORGORDERDTKEY IS NOT NULL AND CD.WKSTATUS <> #{cancelWkstatus} ) TT LEFT JOIN TADMIN_MST_MULAAPMSG_DT MM ON MM.MULAAPMSGHDKEY = 'MSG_' || #{errorCode} AND MM.LAKEY = COALESCE(#{lakey}, 'KOR') WHERE TT.CNT > 0 GROUP BY TT.OWKEY, TT.ORGORDERKEY

/* oms-ordercommon-sql-oracle.xml selectCoMultipleList */ SELECT T.OWKEY , T.CUSTOMERORDERKEY , T.CUSTOMERORDERDTKEY , #{errorCode} AS ORDER_ERROR_CD , REPLACE(#{errorMessage}, #{param1}, T.ICKEY || ':' || T.ICUTTYPE) AS ORDER_ERROR_COMMENTS FROM ( SELECT AGG.OWKEY , AGG.CUSTOMERORDERKEY , MAX(AGG.CUSTOMERORDERDTKEY ) AS CUSTOMERORDERDTKEY , AGG.ICKEY , AGG.ICNM , AGG.ICUTTYPE , SUM(AGG.CONVERTQTY) AS CONVERTQTY , AGG.IC_RATE , AGG.BONUS_IC_RATE , AGG.ICUTQTY , CASE WHEN SUM(AGG.FIRST_CHECK ) > 0 THEN 1 /* 각각 로우가 정수가 떨어지지 않을 때*/ WHEN SUM(AGG.CONVERTQTY) / AGG.ICUTQTY != TRUNC(SUM(AGG.CONVERTQTY) / AGG.ICUTQTY ,0) THEN 1 /* 합산EA 최종 단위에 정수로 떨어지지 않은 경우*/ WHEN SUM(AGG.CONVERTQTY) / (AGG.IC_RATE + AGG.BONUS_IC_RATE) != TRUNC( SUM(AGG.CONVERTQTY) / (AGG.IC_RATE + AGG.BONUS_IC_RATE ),0) THEN 1 /*최종배수 수량이 정수로 떨어지지 않은 경우*/ ELSE 0 END AS SECOND_CHK FROM ( SELECT B.OWKEY , B.CUSTOMERORDERKEY , D.CUSTOMERORDERDTKEY , D.ICKEY , E.ICNM , D.SALEUNIT , E.UOM , F.ICUTQTY , F.ICUTTYPE , D.CONVERTQTY , D.IC_RATE , D.BONUS_IC_RATE , C.OWSPCVERIFICATION , MAX( CAST(D.CUSTOMERORDERDTKEY AS NUMERIC) ) OVER (PARTITION BY D.CUSTOMERORDERKEY ) AS VAL , CASE WHEN COALESCE(D.IC_RATE, 0)=0 OR COALESCE(D.BONUS_IC_RATE, 0)=0 THEN 1 WHEN D.CONVERTQTY / ( CASE WHEN D.INDIAMT > 0 THEN D.IC_RATE ELSE D.BONUS_IC_RATE END ) != TRUNC( D.CONVERTQTY / ( CASE WHEN D.INDIAMT > 0 THEN D.IC_RATE ELSE D.BONUS_IC_RATE END ),0) THEN 1 ELSE 0 END AS FIRST_CHECK
FROM TORDER_INTF_OB_HD A INNER JOIN TORDER_INFO_CO_HD B ON A.EXTERNORDERKEY = B.EXTERNORDERKEY AND A.INTERFACE_ID = B.INTERFACE_ID AND B.WKSTATUS NOT IN (#{cancelWkstatus}, #{failWkstatus}) INNER JOIN TORDER_MST_ORTYPE C ON B.OWKEY = C.OWKEY AND B.OR_TYPE_CD = C.OR_TYPE_CD INNER JOIN TORDER_INFO_CO_DT D ON B.OWKEY = D.OWKEY AND B.CUSTOMERORDERKEY = D.CUSTOMERORDERKEY INNER JOIN TADMIN_MST_IC E ON D.OWKEY = E.OWKEY AND D.ICKEY = E.ICKEY INNER JOIN ( SELECT WU.OWKEY, WU.ICUTKEY, WU.CTKEY , (ARRAY_AGG(WU.ICUTTYPE ORDER BY WU.ICUTQTY, WU.VOLUME, WU.ICUTORDER DESC))[array_upper(ARRAY_AGG(WU.ICUTTYPE ORDER BY WU.ICUTQTY, WU.VOLUME, WU.ICUTORDER DESC), 1)] AS ICUTTYPE , (ARRAY_AGG(WU.ICUTQTY ORDER BY WU.ICUTQTY, WU.VOLUME, WU.ICUTORDER DESC))[array_upper(ARRAY_AGG(WU.ICUTQTY ORDER BY WU.ICUTQTY, WU.VOLUME, WU.ICUTORDER DESC), 1)] AS ICUTQTY FROM TWORK_MST_ICUTXTYPE WU WHERE WU.OWKEY = #{owkey} AND WU.OUTBOUNDUSEYN ='Y' GROUP BY WU.OWKEY, WU.ICUTKEY, WU.CTKEY ) F ON E.OWKEY =F.OWKEY AND E.ICUNITKEY= F.ICUTKEY AND B.CTKEY =F.CTKEY WHERE A.REQUESTDT = #{requestDt} AND A.INTERFACE_ID = #{interfaceId} AND B.OWKEY = #{owkey} AND C.OWSPCVERIFICATION = 'MULTIPLE'
FROM (
SELECT #{item.cohdkey} AS COHDKEY /*CO번호*/
) A INNER JOIN TORDER_INFO_CO_HD B ON A.CUSTOMERORDERKEY = B.CUSTOMERORDERKEY AND B.WKSTATUS NOT IN (#{cancelWkstatus}, #{failWkstatus}) INNER JOIN TORDER_MST_ORTYPE C ON B.OWKEY = C.OWKEY AND B.OR_TYPE_CD = C.OR_TYPE_CD INNER JOIN TORDER_INFO_CO_DT D ON B.OWKEY = D.OWKEY AND B.CUSTOMERORDERKEY = D.CUSTOMERORDERKEY INNER JOIN TADMIN_MST_IC E ON D.OWKEY = E.OWKEY AND D.ICKEY = E.ICKEY INNER JOIN ( SELECT WU.OWKEY, WU.ICUTKEY, WU.CTKEY , (ARRAY_AGG(WU.ICUTTYPE ORDER BY WU.ICUTQTY, WU.VOLUME, WU.ICUTORDER DESC))[array_upper(ARRAY_AGG(WU.ICUTTYPE ORDER BY WU.ICUTQTY, WU.VOLUME, WU.ICUTORDER DESC), 1)] AS ICUTTYPE , (ARRAY_AGG(WU.ICUTQTY ORDER BY WU.ICUTQTY, WU.VOLUME, WU.ICUTORDER DESC))[array_upper(ARRAY_AGG(WU.ICUTQTY ORDER BY WU.ICUTQTY, WU.VOLUME, WU.ICUTORDER DESC), 1)] AS ICUTQTY FROM TWORK_MST_ICUTXTYPE WU WHERE WU.OWKEY = #{owkey} AND WU.OUTBOUNDUSEYN ='Y' GROUP BY WU.OWKEY, WU.ICUTKEY, WU.CTKEY ) F ON E.OWKEY =F.OWKEY AND E.ICUNITKEY= F.ICUTKEY AND B.CTKEY =F.CTKEY WHERE B.OWKEY = #{owkey} AND C.OWSPCVERIFICATION = 'MULTIPLE'
) AGG GROUP BY AGG.OWKEY , AGG.CUSTOMERORDERKEY , AGG.ICKEY , AGG.ICNM , AGG.ICUTTYPE , AGG.IC_RATE , AGG.BONUS_IC_RATE , AGG.ICUTQTY ) T WHERE T.SECOND_CHK > 0

/* oms-ordercommon-sql-oracle.xml selectCoMultiMultipleList */ SELECT T.UPLOADSEQ , T.UPLOADGRPKEY , T.ICKEY , #{errorCode} AS ORDER_ERROR_CD , REPLACE(#{errorMessage}, #{param1}, T.ICKEY || ':' || T.ICUTTYPE) AS ORDER_ERROR_COMMENTS FROM ( SELECT AGG.OWKEY , AGG.UPLOADGRPKEY , MAX(AGG.UPLOADSEQ) AS UPLOADSEQ , AGG.ICKEY , AGG.ICNM , AGG.ICUTTYPE , SUM(AGG.CONVERTQTY) AS CONVERTQTY , AGG.IC_RATE , AGG.BONUS_IC_RATE , AGG.ICUTQTY , CASE WHEN SUM(AGG.FIRST_CHECK ) > 0 THEN 1 /* 각각 로우가 정수가 떨어지지 않을 때*/ WHEN SUM(AGG.CONVERTQTY) / AGG.ICUTQTY != TRUNC(SUM(AGG.CONVERTQTY) / AGG.ICUTQTY ,0) THEN 1 /* 합산EA 최종 단위에 정수로 떨어지지 않은 경우*/ WHEN SUM(AGG.CONVERTQTY) / (AGG.IC_RATE + AGG.BONUS_IC_RATE) != TRUNC( SUM(AGG.CONVERTQTY) / (AGG.IC_RATE + AGG.BONUS_IC_RATE ),0) THEN 1 /*최종배수 수량이 정수로 떨어지지 않은 경우*/ ELSE 0 END AS SECOND_CHK FROM ( SELECT C.OWKEY , A.UPLOADGRPKEY , A.UPLOADSEQ , A.ICKEY , E.ICNM , E.UOM , F.ICUTQTY , F.ICUTTYPE , A.ORDERQTY * IU.ICUNITQTY AS CONVERTQTY , A.IC_RATE , A.BONUS_IC_RATE , C.OWSPCVERIFICATION , CASE WHEN COALESCE(A.IC_RATE, 0)=0 OR COALESCE(A.BONUS_IC_RATE, 0)=0 THEN 1 WHEN A.ORDERQTY * IU.ICUNITQTY / ( CASE WHEN UC.ICRATETYPE='10' THEN A.IC_RATE ELSE A.BONUS_IC_RATE END ) != TRUNC( A.ORDERQTY * IU.ICUNITQTY / ( CASE WHEN UC.ICRATETYPE='10' THEN A.IC_RATE ELSE A.BONUS_IC_RATE END ),0) THEN 1 ELSE 0 END AS FIRST_CHECK FROM (
SELECT #{item.owkey} AS OWKEY , #{item.uploadkey} AS UPLOADKEY , #{item.uploadgrpkey} AS UPLOADGRPKEY , #{item.uploadseq} AS UPLOADSEQ , #{item.ickey} AS ICKEY , #{item.unit} AS UNIT , #{item.orderqty} AS ORDERQTY , #{item.icRate} AS IC_RATE , #{item.bonusIcRate} AS BONUS_IC_RATE
) A INNER JOIN TORDER_UPLOAD_CUSTOMER UC ON A.UPLOADKEY = UC.UPLOADKEY AND A.UPLOADSEQ = UC.UPLOADSEQ INNER JOIN TORDER_MST_ORTYPE C ON A.OWKEY = C.OWKEY AND UC.OR_TYPE_CD = C.OR_TYPE_CD INNER JOIN TADMIN_MST_IC E ON A.OWKEY = E.OWKEY AND A.ICKEY = E.ICKEY INNER JOIN TADMIN_MST_ICUTXTYPE IU ON E.OWKEY = IU.OWKEY AND E.ICUNITKEY = IU.ICUNITKEY AND A.UNIT = IU.ICUNITTYPE INNER JOIN ( SELECT WU.OWKEY, WU.ICUTKEY, WU.CTKEY , (ARRAY_AGG(WU.ICUTTYPE ORDER BY WU.ICUTQTY, WU.VOLUME, WU.ICUTORDER DESC))[array_upper(ARRAY_AGG(WU.ICUTTYPE ORDER BY WU.ICUTQTY, WU.VOLUME, WU.ICUTORDER DESC), 1)] AS ICUTTYPE , (ARRAY_AGG(WU.ICUTQTY ORDER BY WU.ICUTQTY, WU.VOLUME, WU.ICUTORDER DESC))[array_upper(ARRAY_AGG(WU.ICUTQTY ORDER BY WU.ICUTQTY, WU.VOLUME, WU.ICUTORDER DESC), 1)] AS ICUTQTY FROM TWORK_MST_ICUTXTYPE WU WHERE WU.OWKEY = #{owkey} AND WU.OUTBOUNDUSEYN ='Y' GROUP BY WU.OWKEY, WU.ICUTKEY, WU.CTKEY ) F ON E.OWKEY =F.OWKEY AND E.ICUNITKEY= F.ICUTKEY AND UC.CTKEY =F.CTKEY WHERE C.OWSPCVERIFICATION = 'MULTIPLE' ) AGG GROUP BY AGG.OWKEY , AGG.UPLOADGRPKEY , AGG.ICKEY , AGG.ICNM , AGG.ICUTTYPE , AGG.IC_RATE , AGG.BONUS_IC_RATE , AGG.ICUTQTY ) T WHERE T.SECOND_CHK > 0

mapper.update:
/* oms-ordercommon-sql-oracle.xml updateInRequireCoHd */ UPDATE TORDER_INFO_CO_HD H SET (WKSTATUS , ORDERERRCD , ORDERERRCMT , UPDATEDATE , UPDATEURKEY ) = ( SELECT CASE WHEN T.ERRCOL IS NULL THEN #{successWkstatus} ELSE #{failWkstatus} END AS WKSTATUS , CASE WHEN T.ERRCOL IS NULL THEN #{successCode} ELSE EL.MESSAGE_CODE END AS ORDER_ERROR_CD , CASE WHEN T.ERRCOL IS NULL THEN NULL ELSE REPLACE(REPLACE(COALESCE(MM.DISPLAYMSG, EL.SERVER_MESSAGE), #{param1}, COALESCE(ML.DISPLAYMSG, EL.PARAM)), #{param0}, COALESCE(ML.DISPLAYMSG, EL.PARAM)) END AS ORDER_ERROR_COMMENTS , #{interfaceDate} AS UPDATEDATE , #{interfaceUrkey} AS UPDATEURKEY FROM ( SELECT TC.WKSTATUS , TC.COHDKEY , TC.DLVYEXPCTDAY , TC.CLAIMNO , CASE WHEN TC.OWKEY IS NULL THEN 'OWKEY' WHEN TC.EXTORDERTYPECD IS NULL THEN 'EXTORDERTYPECD' WHEN TC.ORDERTYPECD IS NULL THEN 'OR_TYPE_CD' WHEN OW.OWKEY IS NULL THEN 'OWKEY_M' WHEN ET.OWKEY IS NULL THEN 'EXTORDERTYPECD_M' WHEN OT.OWKEY IS NULL THEN 'OR_TYPE_CD_M' ELSE NULL END AS ERRCOL
FROM ( SELECT REQORDERNO, CLAIMNO-- DLVYEXPCTDAY FROM TORDER_INTF_IBORDER_HD WHERE IFID = #{interfaceId} AND REQUESTDT = #{requestDt} ) TI JOIN TORDER_INFO_CO_HD TC ON (TI.REQORDERNO = TC.REQORDERNO OR TI.CLAIMNO = TC.CLAIMNO) --AND TI.DLVYEXPCTDAY = TC.DLVYEXPCTDAY AND TC.IFID = #{interfaceId} AND TC.WKSTATUS NOT IN ( #{cancelWkstatus}, #{failWkstatus}) AND TC.OWKEY = #{owkey}
FROM (
SELECT #{item.cohdkey} AS COHDKEY /*CO번호*/
) TI JOIN TORDER_INFO_CO_HD TC ON TI.COHDKEY = TC.COHDKEY AND TC.WKSTATUS NOT IN ( #{cancelWkstatus}, #{failWkstatus}) AND TC.OWKEY = #{owkey}
LEFT JOIN TORDER_MST_OW OW ON TC.OWKEY = OW.OWKEY LEFT JOIN TORDER_MST_EXTERN ET ON TC.OWKEY = ET.OWKEY AND TC.EXTORDERTYPECD = ET.EXTORDERTYPECD LEFT JOIN TORDER_MST_ORTYPE OT ON TC.OWKEY = OT.OWKEY AND TC.ORDERTYPECD = OT.ORDERTYPECD ) T LEFT JOIN (
) EL ON T.ERRCOL = EL.COCOLUMN LEFT JOIN TADMIN_MST_MULAAPMSG_DT ML ON EL.PARAM = ML.MULAAPMSGHDKEY AND ML.LAKEY = COALESCE(#{lakey}, 'KOR') LEFT JOIN TADMIN_MST_MULAAPMSG_DT MM ON 'MSG_' || EL.MESSAGE_CODE = MM.MULAAPMSGHDKEY AND MM.LAKEY = COALESCE(#{lakey}, 'KOR') WHERE T.COHDKEY = H.COHDKEY AND T.DLVYEXPCTDAY = H.DLVYEXPCTDAY AND H.WKSTATUS NOT IN ( #{cancelWkstatus}, #{failWkstatus}) ) WHERE EXISTS ( SELECT 1
FROM ( SELECT REQORDERNO, CLAIMNO-- DLVYEXPCTDAY FROM TORDER_INTF_IBORDER_HD WHERE IFID = #{interfaceId} AND REQUESTDT = #{requestDt} ) INTF WHERE 1 = 1 AND (INTF.REQORDERNO = H.REQORDERNO OR INTF.CLAIMNO = H.CLAIMNO) --ADN INTF.IFID = H.IFID -- INTF.REQORDERNO = H.REQORDERNO --AND INTF.DLVYEXPCTDAY = H.DLVYEXPCTDAY AND H.IFID = #{interfaceId} AND H.WKSTATUS NOT IN ( #{cancelWkstatus}, #{failWkstatus}) AND H.OWKEY = #{owkey}
FROM (
SELECT #{item.cohdkey} AS COHDKEY /*CO번호*/
) TI WHERE TI.COHDKEY = H.COHDKEY AND H.WKSTATUS NOT IN ( #{cancelWkstatus}, #{failWkstatus}) AND H.OWKEY = #{owkey}
)

/* oms-ordercommon-sql-oracle.xml updateOutRequireCoHd */ UPDATE TORDER_INFO_CO_HD H SET (WKSTATUS , ORDERERRCD , ORDERERRCMT , UPDATEDATE , UPDATEURKEY ) = ( SELECT CASE WHEN T.ERRCOL IS NULL THEN #{successWkstatus} ELSE #{failWkstatus} END AS WKSTATUS , CASE WHEN T.ERRCOL IS NULL THEN #{successCode} ELSE EL.MESSAGE_CODE END AS ORDER_ERROR_CD , CASE WHEN T.ERRCOL IS NULL THEN NULL ELSE REPLACE(REPLACE(COALESCE(MM.DISPLAYMSG, EL.SERVER_MESSAGE), #{param1}, COALESCE(ML.DISPLAYMSG, EL.PARAM)), #{param0}, COALESCE(ML.DISPLAYMSG, EL.PARAM)) END AS ORDER_ERROR_COMMENTS , #{interfaceDate} AS UPDATEDATE , #{interfaceUrkey} AS UPDATEURKEY FROM ( SELECT TC.WKSTATUS , TC.COHDKEY , TC.DLVYEXPCTDAY , CASE WHEN TC.OWKEY IS NULL THEN 'OWKEY' WHEN TC.EXTORDERTYPECD IS NULL THEN 'EXTORDERTYPECD' WHEN TC.ORDERTYPECD IS NULL THEN 'OR_TYPE_CD' WHEN OW.OWKEY IS NULL THEN 'OWKEY_M' WHEN ET.OWKEY IS NULL THEN 'EXTORDERTYPECD_M' WHEN OT.OWKEY IS NULL THEN 'OR_TYPE_CD_M' ELSE NULL END AS ERRCOL
FROM ( SELECT ORGORDERKEY, CLAIMNO ,EXTORDERTYPECD FROM TORDER_INTF_OBORDER_HD WHERE IFID = #{interfaceId} AND REQUESTDT = #{requestDt} ) TI JOIN TORDER_INFO_CO_HD TC ON TI.ORGORDERKEY = TC.ORGORDERKEY AND TI.EXTORDERTYPECD = TC.EXTORDERTYPECD AND (TI.CLAIMNO IS NULL OR TI.CLAIMNO = TC.CLAIMNO) AND TC.IFID = #{interfaceId} AND TC.WKSTATUS NOT IN ( #{cancelWkstatus}, #{failWkstatus}) AND TC.OWKEY = #{owkey}
FROM (
SELECT #{item.cohdkey} AS COHDKEY /*CO번호*/
) TI JOIN TORDER_INFO_CO_HD TC ON TI.COHDKEY = TC.COHDKEY
AND TC.WKSTATUS NOT IN ( #{cancelWkstatus}) AND TC.OWKEY = #{owkey}
LEFT JOIN TORDER_MST_OW OW ON TC.OWKEY = OW.OWKEY LEFT JOIN TORDER_MST_EXTERN ET ON TC.OWKEY = ET.OWKEY AND TC.EXTORDERTYPECD = ET.EXTORDERTYPECD LEFT JOIN TORDER_MST_ORTYPE OT ON TC.OWKEY = OT.OWKEY AND TC.ORDERTYPECD = OT.ORDERTYPECD ) T LEFT JOIN (
) EL ON T.ERRCOL = EL.COCOLUMN LEFT JOIN TADMIN_MST_MULAAPMSG_DT ML ON EL.PARAM = ML.MULAAPMSGHDKEY AND ML.LAKEY = COALESCE(#{lakey}, 'KOR') LEFT JOIN TADMIN_MST_MULAAPMSG_DT MM ON 'MSG_' || EL.MESSAGE_CODE = MM.MULAAPMSGHDKEY AND MM.LAKEY = COALESCE(#{lakey}, 'KOR') WHERE T.COHDKEY = H.COHDKEY AND T.DLVYEXPCTDAY = H.DLVYEXPCTDAY
AND H.WKSTATUS NOT IN ( #{cancelWkstatus}, #{failWkstatus})
AND H.WKSTATUS NOT IN ( #{cancelWkstatus})
) WHERE EXISTS ( SELECT 1
FROM ( SELECT ORGORDERKEY, CLAIMNO ,EXTORDERTYPECD FROM TORDER_INTF_OBORDER_HD WHERE IFID = #{interfaceId} AND REQUESTDT = #{requestDt} ) TI JOIN TORDER_INFO_CO_HD TH ON TI.ORGORDERKEY = TH.ORGORDERKEY AND TI.EXTORDERTYPECD = TH.EXTORDERTYPECD AND (TI.CLAIMNO IS NULL OR TI.CLAIMNO = TH.CLAIMNO) AND H.IFID = #{interfaceId} AND H.WKSTATUS NOT IN ( #{cancelWkstatus}, #{failWkstatus}) AND H.OWKEY = #{owkey}
FROM (
SELECT #{item.cohdkey} AS COHDKEY /*CO번호*/
) TI WHERE TI.COHDKEY = H.COHDKEY
AND H.WKSTATUS NOT IN ( #{cancelWkstatus}) AND H.OWKEY = #{owkey}
)

/* oms-ordercommon-sql-oracle.xml updateInRequireCoDt */ UPDATE TORDER_INFO_CO_DT H SET (WKSTATUS , ORDERERRCD , ORDERERRCMT , UPDATEDATE , UPDATEURKEY ) = ( SELECT CASE WHEN T.ERRCOL IS NULL THEN #{successWkstatus} ELSE #{failWkstatus} END AS WKSTATUS , CASE WHEN T.ERRCOL IS NULL THEN #{successCode} ELSE EL.MESSAGE_CODE END AS ORDER_ERROR_CD , CASE WHEN T.ERRCOL IS NULL THEN NULL ELSE REPLACE(REPLACE(COALESCE(MM.DISPLAYMSG, EL.SERVER_MESSAGE), #{param1}, COALESCE(ML.DISPLAYMSG, EL.PARAM)), #{param0}, COALESCE(ML.DISPLAYMSG, EL.PARAM)) END AS ORDER_ERROR_COMMENTS , #{interfaceDate} AS UPDATEDATE , #{interfaceUrkey} AS UPDATEURKEY FROM ( SELECT TC.WKSTATUS , TC.COHDKEY , TC.CODTKEY , TC.DLVYEXPCTDAY , CASE WHEN TC.OWKEY IS NULL THEN 'OWKEY' WHEN TC.ICKEY IS NULL THEN 'ICKEY' WHEN OW.OWKEY IS NULL THEN 'OWKEY_M' WHEN IC.OWKEY IS NULL THEN 'ICKEY_M' ELSE NULL END AS ERRCOL
