/* oms-ordercommon-sql-oracle.xml updateValidateUploadCoItem */ UPDATE TORDER_UPLOAD_CUSTOMER H SET (ORDER_ERROR_CD , ORDER_ERROR_COMMENTS , UPDATEDATE , UPDATEURKEY ) = ( SELECT T.ORDER_ERROR_CD /*주문오류 코드*/ , T.ORDER_ERROR_COMMENTS /*주문생성 오류비고*/ , #{interfaceDate} AS UPDATEDATE /*수정 일시*/ , #{interfaceUrkey} AS UPDATEURKEY /*수정 사용자 ID*/ FROM (
SELECT #{item.uploadkey} AS UPLOADKEY , #{item.ackey} AS ACKEY /*공급처*/ , #{item.deliveryKey} AS DELIVERY_KEY /*배송처*/ , #{item.storeKey} AS STORE_KEY /*판매처*/ , #{item.ctkey} AS CTKEY /*센터코드*/ , #{item.deliveryHdDt} AS DELIVERY_HD_DT /*예정일자*/ , #{item.orHdDt} AS OR_HD_DT /*지시일자*/ , #{item.orTypeCd} AS OR_TYPE_CD /*주문유형*/ , #{item.extordertypecd} AS EXTORDERTYPECD /*화주주문유형*/ , #{item.comments} AS COMMENTS /*헤더기준 비고*/ , #{item.errorCode} AS ORDER_ERROR_CD /*주문오류 코드*/ , #{item.serverMessage} AS ORDER_ERROR_COMMENTS /*주문생성 오류비고*/ , #{item.externorderkey} AS EXTERNORDERKEY
) T WHERE T.UPLOADKEY = H.UPLOADKEY AND COALESCE(T.ACKEY, 'X') = COALESCE(H.ACKEY, 'X') AND COALESCE(T.DELIVERY_KEY, 'X') = COALESCE(H.DELIVERY_KEY, 'X') AND COALESCE(T.STORE_KEY, 'X') = COALESCE(H.STORE_KEY, 'X') AND COALESCE(T.CTKEY, 'X') = COALESCE(H.CTKEY, 'X') AND COALESCE(T.DELIVERY_HD_DT, 'X') = COALESCE(H.DELIVERY_HD_DT, 'X') AND COALESCE(T.OR_HD_DT, 'X') = COALESCE(H.OR_HD_DT, 'X') AND COALESCE(T.OR_TYPE_CD, 'X') = COALESCE(H.OR_TYPE_CD, 'X') AND COALESCE(T.EXTORDERTYPECD, 'X') = COALESCE(H.EXTORDERTYPECD, 'X') AND COALESCE(T.COMMENTS, 'X') = COALESCE(H.COMMENTS, 'X') AND COALESCE(T.EXTERNORDERKEY, 'X') = COALESCE(H.EXTERNORDERKEY, 'X') ) WHERE EXISTS ( SELECT 1 FROM (
SELECT #{item.uploadkey} AS UPLOADKEY , #{item.ackey} AS ACKEY /*공급처*/ , #{item.deliveryKey} AS DELIVERY_KEY /*배송처*/ , #{item.storeKey} AS STORE_KEY /*판매처*/ , #{item.ctkey} AS CTKEY /*센터코드*/ , #{item.deliveryHdDt} AS DELIVERY_HD_DT /*예정일자*/ , #{item.orHdDt} AS OR_HD_DT /*지시일자*/ , #{item.orTypeCd} AS OR_TYPE_CD /*주문유형*/ , #{item.extordertypecd} AS EXTORDERTYPECD /*화주주문유형*/ , #{item.comments} AS COMMENTS /*헤더기준 비고*/ , #{item.externorderkey} AS EXTERNORDERKEY
) INTF WHERE INTF.UPLOADKEY = H.UPLOADKEY AND COALESCE(INTF.ACKEY, 'X') = COALESCE(H.ACKEY, 'X') AND COALESCE(INTF.DELIVERY_KEY, 'X') = COALESCE(H.DELIVERY_KEY, 'X') AND COALESCE(INTF.STORE_KEY, 'X') = COALESCE(H.STORE_KEY, 'X') AND COALESCE(INTF.CTKEY, 'X') = COALESCE(H.CTKEY, 'X') AND COALESCE(INTF.DELIVERY_HD_DT, 'X') = COALESCE(H.DELIVERY_HD_DT, 'X') AND COALESCE(INTF.OR_HD_DT, 'X') = COALESCE(H.OR_HD_DT, 'X') AND COALESCE(INTF.OR_TYPE_CD, 'X') = COALESCE(H.OR_TYPE_CD, 'X') AND COALESCE(INTF.EXTORDERTYPECD, 'X') = COALESCE(H.EXTORDERTYPECD, 'X') AND COALESCE(INTF.COMMENTS, 'X') = COALESCE(H.COMMENTS, 'X') AND COALESCE(INTF.EXTERNORDERKEY, 'X') = COALESCE(H.EXTERNORDERKEY, 'X') )

/* oms-ordercommon-sql-oracle.xml updateValidateUploadCoItem */ UPDATE TORDER_UPLOAD_CUSTOMER H SET (ORDER_ERROR_CD , ORDER_ERROR_COMMENTS , UPDATEDATE , UPDATEURKEY ) = ( SELECT T.ORDER_ERROR_CD /*주문오류 코드*/ , T.ORDER_ERROR_COMMENTS /*주문생성 오류비고*/ , #{interfaceDate} AS UPDATEDATE /*수정 일시*/ , #{interfaceUrkey} AS UPDATEURKEY /*수정 사용자 ID*/ FROM (
SELECT #{item.uploadkey} AS UPLOADKEY , #{item.uploadseq} AS UPLOADSEQ , #{item.errorCode} AS ORDER_ERROR_CD /*주문오류 코드*/ , #{item.serverMessage} AS ORDER_ERROR_COMMENTS /*주문생성 오류비고*/
) T WHERE T.UPLOADKEY = H.UPLOADKEY AND T.UPLOADSEQ = H.UPLOADSEQ ) WHERE EXISTS ( SELECT 1 FROM (
SELECT #{item.uploadkey} AS UPLOADKEY , #{item.uploadseq} AS UPLOADSEQ
) INTF WHERE INTF.UPLOADKEY = H.UPLOADKEY AND INTF.UPLOADSEQ = H.UPLOADSEQ )

mapper.select:
      /* oms-ordercommon-sql-oracle.xml selectInErrorCoList */
      SELECT TC.*
           , OM.MALPERFMANSYN
	    FROM (
 	    		SELECT REQORDERNO, CLAIMNO-- DLVYEXPCTDAY 
	 	  		  FROM TORDER_INTF_IBORDER_HD
	 	  		 WHERE IFID = #{interfaceId}
 	    		   AND REQUESTDT = #{requestDt}
 	    	  ) TI
 	     JOIN TORDER_INFO_CO_HD TC
 	       ON (TI.REQORDERNO = TC.REQORDERNO OR TI.CLAIMNO = TC.CLAIMNO)	
 	      --AND TI.DLVYEXPCTDAY = TC.DLVYEXPCTDAY
 	      AND TC.IFID = #{interfaceId}
 	      AND TC.WKSTATUS = #{failWkstatus}
 	      AND TC.OWKEY = #{owkey}    
 	      JOIN TORDER_INFO_ORTYPE_MAPPING OM  
 	      ON TC.OWKEY = OM.OWKEY 
 	      AND TC.EXTORDERTYPECD = OM.EXTORDERTYPECD

      /* oms-ordercommon-sql-oracle.xml selectOutErrorCoList */
      SELECT TC.*
           , OM.MALPERFMANSYN
	    FROM (
 	    		SELECT ORGORDERKEY, CLAIMNO -- DLVYEXPCTDAY 
	 	  		  FROM TORDER_INTF_OBORDER_HD
	 	  		 WHERE IFID = #{interfaceId}
 	    		   AND REQUESTDT = #{requestDt}
 	    	  ) TI
 	     JOIN TORDER_INFO_CO_HD TC
 	       ON (TI.ORGORDERKEY = TC.ORGORDERKEY OR TI.CLAIMNO = TC.CLAIMNO)		
 	      --AND TI.DLVYEXPCTDAY = TC.DLVYEXPCTDAY
 	      AND TC.IFID = #{interfaceId}
 	      AND TC.WKSTATUS = #{failWkstatus}
 	      AND TC.OWKEY = #{owkey}   
 	      JOIN TORDER_INFO_ORTYPE_MAPPING OM  
 	      ON TC.OWKEY = OM.OWKEY 
 	      AND TC.EXTORDERTYPECD = OM.EXTORDERTYPECD

mapper.insert:
/* oms-ordercommon-sql-oracle.xml insertInCoToSoHd */ INSERT INTO TORDER_INFO_SO_HD ( OWKEY /*화주코드*/ , SOHDKEY /*S/O번호*/ , DLVYEXPCTDAY /*배송예정일자*/ , ORDERISTDAY /*지시일자*/ , ORDERTYPECD /*주문오더유형*/ , WKSTATUS /*작업(주문) 상태*/ , CTKEY /*센터코드*/ , DLVYACKEY /*납품처코드*/ , STOREKEY /*판매처코드*/ , BILLKEY /*정산처코드*/ , PAYERKEY /*청구처코드*/ , ACKEY /*공급처코드*/ , LOGGRPCD /*상/저온 구분*/ , ORGORDERKEY /*외부주문번호*/ , FROMTOCTKEY /*물품 이동 센터*/ , ICGRTYPE /*물품그룹유형*/ , ICGRKEY /*물품그룹코드*/ , POTYPE /*PO타입*/ , RFRNCKEY /*이전참조문서번호*/ , SALESEMPID /*영업사원ID*/ , DLVYEMPID /*배송사원ID*/ , EDIYN /*EDI 등록 여부*/ , CMT /*비고*/ , ADDCMT01 , ADDCMT02 , CNLYN /*주문취소여부*/ , CNLDATE /*주문취소일시*/ , CNLEMPID /*주문취소ID*/ , ORDERSNDYN /*주문전송여부*/ , ORDERSNDDATE /*주문전송일시*/ , ORDERSNDUSERID /*주문전송ID*/ , COHDKEY /*CO주문번호*/ , EXTORDERTYPECD /*화주오더유형*/ , SHMISTNO , ORDERERRCD /*주문오류 코드*/ , ORDERERRCMT /*주문생성 오류비고*/ , RECPNM , RECPADDRHD , RECPADDRDT , RECPZIPCD , RECPTEL01 , RECPTEL02 , BUYER , BUYERADDRHD , BUYERADDRDT , BUYERZIPCD , BUYERTEL01 , BUYERTEL02 , RECALLER , RECALLERADDRHD , RECALLERADDRDT , RECALLERZIPCD , RECALLERTEL01 , RECALLERTEL02 , RECALLERIYN , RIRSNCD , CLAIMNO , DLVYMETHDCD , DLVYMETHDDTCD , MALORDERDIV , NISYN , NISCNLRNGDIV , PAYMTCOMPLDAY , PARTERID , ACCESSKEY , INSERTDATE /*입력 일시*/ , INSERTURKEY /*입력 사용자 ID*/ , UPDATEDATE /*수정 일시*/ , UPDATEURKEY /*수정 사용자 ID*/ ) SELECT CH.OWKEY /*화주코드*/ , TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDD') || #{orderNoType} || LPAD(nextval('seq_torder_info_so_hd')::TEXT, 6, '0') AS SOHDKEY /*S/O번호*/ , CH.DLVYEXPCTDAY /*배송예정일자*/ , CH.ORDERISTDAY AS OR_DATE /*지시일자*/ , CH.ORDERTYPECD /*주문오더유형*/ , #{wkstatus} AS WKSTATUS /*작업(주문) 상태*/ , CH.CTKEY /*센터코드*/ , CH.DLVYACKEY /*납품처코드*/ , CH.STOREKEY /*판매처코드*/ , CH.BILLKEY /*정산처코드*/ , CH.PAYERKEY /*청구처코드*/ , CH.ACKEY /*공급처코드*/ , COD.LOGGRPCD /*상/저온 구분*/ , CASE WHEN CH.EXTORDERTYPECD = 'DA01' THEN CH.REQORDERNO ELSE CH.ORGORDERKEY END AS ORGORDERKEY , CH.FROMTOCTKEY /*물품 이동 센터*/ , NULL AS ICGRTYPE /*물품그룹유형*/ , NULL AS ICGRKEY /*물품그룹코드*/ , CH.POTYPE /*PO타입*/ , CH.RFRNCKEY /*이전참조문서번호*/ , CH.SALESEMPID /*영업사원ID*/ , CH.DLVYEMPID /*배송사원ID*/ , CH.EDIYN /*EDI 등록 여부*/ , CH.CMT /*비고*/ , CH.ADDCMT01 , CH.ADDCMT02 , 'N' AS CNLYN /*주문취소여부*/ , NULL AS CNLDATE /*주문취소일시*/ , NULL AS CNLEMPID /*주문취소ID*/ , 'N' AS ORDERSNDYN /*주문전송여부*/ , NULL AS ORDERSNDDATE /*주문전송일시*/ , NULL AS ORDERSNDID /*주문전송ID*/ , CH.COHDKEY /*CO주문번호*/ , CH.EXTORDERTYPECD /*화주오더유형*/ , CH.SHMISTNO , NULL AS ORDERERRCD /*주문오류 코드*/ , NULL AS ORDERERRCMT /*주문생성 오류비고*/ , CH.RECPNM , CH.RECPADDRHD , CH.RECPADDRDT , CH.RECPZIPCD , CH.RECPTEL01 , CH.RECPTEL02 , CH.BUYER , CH.BUYERADDRHD , CH.BUYERADDRDT , CH.BUYERZIPCD , CH.BUYERTEL01 , CH.BUYERTEL02 , CH.RECALLER , CH.RECALLERADDRHD , CH.RECALLERADDRDT , CH.RECALLERZIPCD , CH.RECALLERTEL01 , CH.RECALLERTEL02 , CH.RECALLERIYN , CH.RIRSNCD , CH.CLAIMNO , CH.DLVYMETHDCD , CH.DLVYMETHDDTCD , CH.MALORDERDIV , CH.NISYN , CH.NISCNLRNGDIV , CH.PAYMTCOMPLDAY , CH.PARTERID , CH.ACCESSKEY , #{interfaceDate} AS INSERTDATE /*입력 일시*/ , #{interfaceUrkey} AS INSERTURKEY /*입력 사용자 ID*/ , #{interfaceDate} AS UPDATEDATE /*수정 일시*/ , #{interfaceUrkey} AS UPDATEURKEY /*수정 사용자 ID*/ FROM TORDER_INFO_CO_HD CH JOIN (
SELECT #{item.cohdkey} AS COHDKEY
SELECT TH.COHDKEY FROM ( SELECT REQORDERNO, CLAIMNO-- DLVYEXPCTDAY FROM TORDER_INTF_IBORDER_HD WHERE IFID = #{interfaceId} AND REQUESTDT = #{requestDt} ) TI JOIN TORDER_INFO_CO_HD TH ON (TI.REQORDERNO = TH.REQORDERNO OR TI.CLAIMNO = TH.CLAIMNO) --AND TI.DLVYEXPCTDAY = TH.DLVYEXPCTDAY AND TH.IFID = #{interfaceId} AND TH.WKSTATUS <> #{cancelWkstatus} AND TH.OWKEY = #{owkey}
) CO ON CH.COHDKEY = CO.COHDKEY JOIN ( SELECT CD.COHDKEY , MAX(CD.LOGGRPCD) AS LOGGRPCD FROM TORDER_INFO_CO_DT CD JOIN (
SELECT #{item.cohdkey} AS COHDKEY
SELECT TH.COHDKEY FROM ( SELECT REQORDERNO, CLAIMNO-- DLVYEXPCTDAY FROM TORDER_INTF_IBORDER_HD WHERE IFID = #{interfaceId} AND REQUESTDT = #{requestDt} ) TI JOIN TORDER_INFO_CO_HD TH ON (TI.REQORDERNO = TH.REQORDERNO OR TI.CLAIMNO = TH.CLAIMNO) --AND TI.DLVYEXPCTDAY = TH.DLVYEXPCTDAY AND TH.IFID = #{interfaceId} AND TH.WKSTATUS <> #{cancelWkstatus} AND TH.OWKEY = #{owkey}
) CDK ON CD.COHDKEY = CDK.COHDKEY GROUP BY CD.COHDKEY ) COD ON CH.COHDKEY = COD.COHDKEY
JOIN TORDER_MST_ORTYPE OT ON CH.OWKEY = OT.OWKEY AND CH.ORDERTYPECD = OT.ORDERTYPECD AND OT.DELYN = 'N' LEFT JOIN TORDER_INFO_SO_HD SH ON CH.CTKEY = SH.CTKEY AND CH.COHDKEY = SH.COHDKEY AND COALESCE(SH.CNLYN, 'N') ='N' /*주문취소여부*/ WHERE CH.OWKEY = #{owkey} AND SH.SOHDKEY IS NULL
AND OT.SOYN = 'Y' /*SO자동생성어부*/
AND CH.WKSTATUS IN
#{wkstatuses}

/* oms-ordercommon-sql-oracle.xml insertOutCoToSoHd */ INSERT INTO TORDER_INFO_SO_HD ( OWKEY /*화주코드*/ , SOHDKEY /*S/O번호*/ , DLVYEXPCTDAY /*배송예정일자*/ , ORDERISTDAY /*지시일자*/ , ORDERTYPECD /*주문오더유형*/ , WKSTATUS /*작업(주문) 상태*/ , CTKEY /*센터코드*/ , DLVYACKEY /*납품처코드*/ , STOREKEY /*판매처코드*/ , BILLKEY /*정산처코드*/ , PAYERKEY /*청구처코드*/ , ACKEY /*공급처코드*/ , LOGGRPCD /*상/저온 구분*/ , ORGORDERKEY /*외부주문번호*/ , FROMTOCTKEY /*물품 이동 센터*/ , ICGRTYPE /*물품그룹유형*/ , ICGRKEY /*물품그룹코드*/ , POTYPE /*PO타입*/ , RFRNCKEY /*이전참조문서번호*/ , SALESEMPID /*영업사원ID*/ , DLVYEMPID /*배송사원ID*/ , EDIYN /*EDI 등록 여부*/ , CMT /*비고*/ , ADDCMT01 , ADDCMT02 , ADDCMT03 , CNLYN /*주문취소여부*/ , CNLDATE /*주문취소일시*/ , CNLEMPID /*주문취소ID*/ , ORDERSNDYN /*주문전송여부*/ , ORDERSNDDATE /*주문전송일시*/ , ORDERSNDUSERID /*주문전송ID*/ , COHDKEY /*CO주문번호*/ , EXTORDERTYPECD /*화주오더유형*/ , SHMISTNO , ORDERERRCD /*주문오류 코드*/ , ORDERERRCMT /*주문생성 오류비고*/ , RECPNM , RECPADDRHD , RECPADDRDT , RECPZIPCD , RECPTEL01 , RECPTEL02 , BUYER , BUYERADDRHD , BUYERADDRDT , BUYERZIPCD , BUYERTEL01 , BUYERTEL02 , RECALLER , RECALLERADDRHD , RECALLERADDRDT , RECALLERZIPCD , RECALLERTEL01 , RECALLERTEL02 , RECALLERIYN , RIRSNCD , CLAIMNO , DLVYMETHDCD , DLVYMETHDDTCD , MALORDERDIV , NISYN , NISCNLRNGDIV , PAYMTCOMPLDAY , PARTERID , ACCESSKEY , INSERTDATE /*입력 일시*/ , INSERTURKEY /*입력 사용자 ID*/ , UPDATEDATE /*수정 일시*/ , UPDATEURKEY /*수정 사용자 ID*/ ) SELECT CH.OWKEY /*화주코드*/ , TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDD') || #{orderNoType} || LPAD(nextval('seq_torder_info_so_hd')::TEXT, 6, '0') AS SOHDKEY /*S/O번호*/ , CH.DLVYEXPCTDAY /*배송예정일자*/ , CH.ORDERISTDAY AS OR_DATE /*지시일자*/ , CH.ORDERTYPECD /*주문오더유형*/ , #{wkstatus} AS WKSTATUS /*작업(주문) 상태*/ , CH.CTKEY /*센터코드*/ , CH.DLVYACKEY /*납품처코드*/ , CH.STOREKEY /*판매처코드*/ , CH.BILLKEY /*정산처코드*/ , CH.PAYERKEY /*청구처코드*/ , CH.ACKEY /*공급처코드*/ , COD.LOGGRPCD /*상/저온 구분*/ , CH.ORGORDERKEY /*외부주문번호*/ , CH.FROMTOCTKEY /*물품 이동 센터*/ , NULL AS ICGRTYPE /*물품그룹유형*/ , NULL AS ICGRKEY /*물품그룹코드*/ , CH.POTYPE /*PO타입*/ , CH.RFRNCKEY /*이전참조문서번호*/ , CH.SALESEMPID /*영업사원ID*/ , CH.DLVYEMPID /*배송사원ID*/ , CH.EDIYN /*EDI 등록 여부*/ , CH.CMT /*비고*/ , CH.ADDCMT01 , CH.ADDCMT02 , CH.ADDCMT03 , 'N' AS CNLYN /*주문취소여부*/ , NULL AS CNLDATE /*주문취소일시*/ , NULL AS CNLEMPID /*주문취소ID*/ , 'N' AS ORDERSNDYN /*주문전송여부*/ , NULL AS ORDERSNDDATE /*주문전송일시*/ , NULL AS ORDERSNDID /*주문전송ID*/ , CH.COHDKEY /*CO주문번호*/ , CH.EXTORDERTYPECD /*화주오더유형*/ , CH.SHMISTNO , NULL AS ORDERERRCD /*주문오류 코드*/ , NULL AS ORDERERRCMT /*주문생성 오류비고*/ , CH.RECPNM , CH.RECPADDRHD , CH.RECPADDRDT , CH.RECPZIPCD , CH.RECPTEL01 , CH.RECPTEL02 , CH.BUYER , CH.BUYERADDRHD , CH.BUYERADDRDT , CH.BUYERZIPCD , CH.BUYERTEL01 , CH.BUYERTEL02 , CH.RECALLER , CH.RECALLERADDRHD , CH.RECALLERADDRDT , CH.RECALLERZIPCD , CH.RECALLERTEL01 , CH.RECALLERTEL02 , CH.RECALLERIYN , CH.RIRSNCD , CH.CLAIMNO , CH.DLVYMETHDCD , CH.DLVYMETHDDTCD , CH.MALORDERDIV , CH.NISYN , CH.NISCNLRNGDIV , CH.PAYMTCOMPLDAY , CH.PARTERID , CH.ACCESSKEY , #{interfaceDate} AS INSERTDATE /*입력 일시*/ , #{interfaceUrkey} AS INSERTURKEY /*입력 사용자 ID*/ , #{interfaceDate} AS UPDATEDATE /*수정 일시*/ , #{interfaceUrkey} AS UPDATEURKEY /*수정 사용자 ID*/ FROM TORDER_INFO_CO_HD CH JOIN (
SELECT #{item.cohdkey} AS COHDKEY
SELECT TH.COHDKEY FROM ( SELECT ORGORDERKEY, CLAIMNO -- DLVYEXPCTDAY FROM TORDER_INTF_OBORDER_HD WHERE IFID = #{interfaceId} AND REQUESTDT = #{requestDt} ) TI JOIN TORDER_INFO_CO_HD TH ON (TI.ORGORDERKEY = TH.ORGORDERKEY OR TI.CLAIMNO = TH.CLAIMNO) --AND TI.DLVYEXPCTDAY = TH.DLVYEXPCTDAY AND TH.IFID = #{interfaceId} AND TH.WKSTATUS <> #{cancelWkstatus} AND TH.OWKEY = #{owkey}
) CO ON CH.COHDKEY = CO.COHDKEY JOIN ( SELECT CD.COHDKEY , MAX(CD.LOGGRPCD) AS LOGGRPCD FROM TORDER_INFO_CO_DT CD JOIN (
SELECT #{item.cohdkey} AS COHDKEY
SELECT TH.COHDKEY FROM ( SELECT ORGORDERKEY, CLAIMNO -- DLVYEXPCTDAY FROM TORDER_INTF_OBORDER_HD WHERE IFID = #{interfaceId} AND REQUESTDT = #{requestDt} ) TI JOIN TORDER_INFO_CO_HD TH ON (TI.ORGORDERKEY = TH.ORGORDERKEY OR TI.CLAIMNO = TH.CLAIMNO) --AND TI.DLVYEXPCTDAY = TH.DLVYEXPCTDAY AND TH.IFID = #{interfaceId} AND TH.WKSTATUS <> #{cancelWkstatus} AND TH.OWKEY = #{owkey}
) CDK ON CD.COHDKEY = CDK.COHDKEY GROUP BY CD.COHDKEY ) COD ON CH.COHDKEY = COD.COHDKEY
JOIN TORDER_MST_ORTYPE OT ON CH.OWKEY = OT.OWKEY AND CH.ORDERTYPECD = OT.ORDERTYPECD AND OT.DELYN = 'N' LEFT JOIN TORDER_INFO_SO_HD SH ON CH.CTKEY = SH.CTKEY AND CH.COHDKEY = SH.COHDKEY AND COALESCE(SH.CNLYN, 'N') ='N' /*주문취소여부*/ WHERE CH.OWKEY = #{owkey} AND SH.SOHDKEY IS NULL
AND OT.SOYN = 'Y' /*SO자동생성어부*/
AND CH.WKSTATUS IN
