/* oms-ordercommon-sql-oracle.xml insertInCoToSoDt */ INSERT INTO TORDER_INFO_SO_DT ( OWKEY /*화주코드*/ , SOHDKEY /*S/O번호*/ , SODTKEY /*S/O상세번호*/ , ICKEY /*제품코드*/ , OLNICKEY , ICUTKEY /*제품단위코드*/ , UOM /*주문단위*/ , INITQTY /*초기수량*/ , EXPCTQTY /*예정수량*/ , CNFRMQTY /*확정수량*/ , SNDQTY /*SAP전송수량*/ , DLVYEXPCTDAY /*배송예정일자*/ , ORDERISTDAY /*지시일자*/ , OBAMT , TTWEIGHT /*총중량*/ , WEIGHTUNIT /*중량단위*/ , VOL /*총부피*/ , VOLUNIT /*부피단위*/ , LOGGRPCD /*상/저온 구분*/ , CMT /*비고*/ , PRDCTLOT /*생산 LOT*/ , PRDCTDAY /*생산일자*/ , WKSTATUS /*작업(주문) 상태*/ , RFRNCKEY /*이전참조문서번호*/ , RFRNCDTKEY /*이전참조상세번호*/ , ORGORDERKEY /*외부주문번호*/ , ORGORDERDTKEY /*외부주문상세번호*/ , SHMISTNO , CNFRMYN , CNLYN /*주문취소여부*/ , NISCMT /*결품사유*/ , RICMT /*반품사유*/ , COHDKEY /*CO주문번호*/ , CODTKEY /*CO주문상세번호*/ , ORDERERRCD /*주문오류 코드*/ , ORDERERRCMT /*주문생성 오류비고*/ , ICGRKEY /*상품그룹*/ , ICGRTYPE /*상품그룹유형*/ , SPEC /*규격*/ , DLVYCNTRUNIT , MALBOXQTY , MALPCSQTY , INSERTDATE /*입력 일시*/ , INSERTURKEY /*입력 사용자 ID*/ , UPDATEDATE /*수정 일시*/ , UPDATEURKEY /*수정 사용자 ID*/ ) SELECT CD.OWKEY /*화주코드*/ , SH.SOHDKEY /*S/O번호*/ , CD.CODTKEY AS SODTKEY /*S/O상세번호*/ , CD.ICKEY /*제품코드*/ , CD.OLNICKEY , IC.ICUNITKEY AS ICUTKEY /*제품단위코드*/ , CD.UNIT AS UOM /*주문단위*/ , CD.INITQTY AS INITQTY /*초기수량*/ , CD.ORDERISTQTY AS EXPCTQTY /*예정수량*/ , 0 AS CFQTY /*확정수량*/ , 0 AS SENDQTY /*SAP전송수량*/ , SH.DLVYEXPCTDAY /*배송예정일자*/ , SH.ORDERISTDAY /*지시일자*/ , 0 AS OBAMT , CD.TTWEIGHT /*총중량*/ , CD.WEIGHTUNIT /*중량단위*/ , CD.VOL /*총부피*/ , CD.VOLUNIT /*부피단위*/ , CD.LOGGRPCD /*상/저온 구분*/ , CD.CMT /*비고*/ , CD.PRDCTLOT /*생산 LOT*/ , CD.PRDCTDAY /*생산일자*/ , #{wkstatus} AS WKSTATUS /*작업(주문) 상태*/ , CASE WHEN CH.EXTORDERTYPECD = 'DA01' THEN CD.REQORDERNO ELSE CD.RFRNCKEY END AS RFRNCKEY , CD.RFRNCDTKEY , CD.ORGORDERKEY /*외부주문번호*/ , CD.ORGORDERDTKEY /*외부주문상세번호*/ , CD.SHMISTNO , 'N' AS CNFRMYN , 'N' AS CNLYN /*주문취소여부*/ , NULL AS NISCMT /*결품사유*/ , NULL AS RICMT /*반품사유*/ , CD.COHDKEY /*CO주문번호*/ , CD.CODTKEY /*CO주문상세번호*/ , NULL AS ORDERERRCD /*주문오류 코드*/ , NULL AS ORDERERRCMT /*주문생성 오류비고*/ , IC.ICGRPKEY /*상품그룹*/ , IC.ICGRPTYPE /*상품그룹유형*/ , IC.SPEC /*규격*/ , CD.DLVYCNTRUNIT , CD.MALBOXQTY , CD.MALPCSQTY , #{interfaceDate} AS INSERTDATE /*입력 일시*/ , #{interfaceUrkey} AS INSERTURKEY /*입력 사용자 ID*/ , #{interfaceDate} AS UPDATEDATE /*수정 일시*/ , #{interfaceUrkey} AS UPDATEURKEY /*수정 사용자 ID*/ FROM TORDER_INFO_CO_HD CH JOIN (
SELECT #{item.cohdkey} AS COHDKEY
SELECT TH.COHDKEY FROM ( SELECT REQORDERNO, CLAIMNO-- DLVYEXPCTDAY FROM TORDER_INTF_IBORDER_HD WHERE IFID = #{interfaceId} AND REQUESTDT = #{requestDt} ) TI JOIN TORDER_INFO_CO_HD TH ON (TI.REQORDERNO = TH.REQORDERNO OR TI.CLAIMNO = TH.CLAIMNO) --AND TI.DLVYEXPCTDAY = TH.DLVYEXPCTDAY AND TH.IFID = #{interfaceId} AND TH.WKSTATUS <> #{cancelWkstatus} AND TH.OWKEY = #{owkey}
) CO ON CH.COHDKEY = CO.COHDKEY JOIN TORDER_INFO_CO_DT CD ON CH.OWKEY = CD.OWKEY AND CH.COHDKEY = CD.COHDKEY JOIN TORDER_MST_ORTYPE OT ON CH.OWKEY = OT.OWKEY AND CH.ORDERTYPECD = OT.ORDERTYPECD AND OT.DELYN = 'N' JOIN TORDER_INFO_SO_HD SH ON CH.OWKEY = SH.OWKEY AND CH.COHDKEY = SH.COHDKEY AND COALESCE(SH.CNLYN, 'N') ='N' /*주문취소여부*/ LEFT JOIN TORDER_INFO_SO_DT SD ON CD.OWKEY = SD.OWKEY AND CD.COHDKEY = SD.COHDKEY AND CD.COHDKEY = SD.COHDKEY AND COALESCE(SD.CNLYN, 'N') ='N' /*주문취소여부*/ LEFT JOIN TORDER_MST_IC IC ON CD.OWKEY = IC.OWKEY AND CD.ICKEY = IC.ICKEY WHERE CH.OWKEY = #{owkey} AND SD.SOHDKEY IS NULL /*혹시 co번호를 가진so가 여러개일 경우에 대비*/
AND OT.SOYN = 'Y' /*SO자동생셩어부*/
AND CH.WKSTATUS IN
#{wkstatuses}

