 /*상품그룹유형*/ , IC.SPEC /*규격*/ , CD.DLVYCNTRUNIT , CD.MALBOXQTY , CD.MALPCSQTY , #{interfaceDate} AS INSERTDATE /*입력 일시*/ , #{interfaceUrkey} AS INSERTURKEY /*입력 사용자 ID*/ , #{interfaceDate} AS UPDATEDATE /*수정 일시*/ , #{interfaceUrkey} AS UPDATEURKEY /*수정 사용자 ID*/ FROM TORDER_INFO_CO_HD CH JOIN (
