SELECT #{item.cohdkey} AS COHDKEY
SELECT TH.COHDKEY FROM ( SELECT REQORDERNO, CLAIMNO-- DLVYEXPCTDAY FROM TORDER_INTF_IBORDER_HD WHERE IFID = #{interfaceId} AND REQUESTDT = #{requestDt} ) TI JOIN TORDER_INFO_CO_HD TH ON (TI.REQORDERNO = TH.REQORDERNO OR TI.CLAIMNO = TH.CLAIMNO) --AND TI.DLVYEXPCTDAY = TH.DLVYEXPCTDAY AND TH.IFID = #{interfaceId} AND TH.WKSTATUS <> #{cancelWkstatus} AND TH.OWKEY = #{owkey}
) VHD ON DT.COHDKEY = VHD.COHDKEY AND DT.OWKEY = #{owkey} JOIN TORDER_INFO_SO_HD SH ON DT.OWKEY = SH.OWKEY AND DT.SOHDKEY = SH.SOHDKEY WHERE 1=1
AND DT.WKSTATUS IN
#{wkstatuses}

/* oms-ordercommon-sql-oracle.xml selectOutCoToSoDt */ SELECT SH.ORDERTYPECD ,DT.OWKEY /*화주코드*/ ,DT.SOHDKEY /*S/O번호*/ ,DT.SODTKEY /*S/O상세번호*/ ,DT.ICKEY /*제품코드*/ ,DT.OLNICKEY ,DT.ICUTKEY /*제품단위코드*/ ,DT.UOM /*주문단위*/ ,DT.INITQTY /*초기수량(EA)*/ ,DT.EXPCTQTY /*예정수량(EA)*/ ,DT.CNFRMQTY /*확정수량(EA)*/ ,DT.SNDQTY /*SAP전송수량(EA)*/ ,DT.DLVYEXPCTDAY /*배송예정일자*/ ,DT.ORDERISTDAY /*지시일자*/ ,DT.OBAMT ,DT.TTWEIGHT /*총중량*/ ,DT.WEIGHTUNIT /*중량단위*/ ,DT.VOL /*총부피*/ ,DT.VOLUNIT /*부피단위*/ ,DT.LOGGRPCD /*상/저온 구분*/ ,DT.CMT /*비고*/ ,DT.PRDCTLOT /*생산 LOT*/ ,DT.PRDCTDAY /*생산일자*/ ,DT.WKSTATUS /*작업(주문) 상태*/ ,DT.RFRNCKEY /*이전참조문서번호*/ ,DT.RFRNCDTKEY /*이전참조상세번호*/ ,DT.ORGORDERKEY /*외부주문번호*/ ,DT.ORGORDERDTKEY /*외부주문상세번호*/ ,DT.CNFRMYN ,DT.CNLYN /*주문취소여부*/ ,DT.NISCMT /*결품사유*/ ,DT.RICMT /*반품사유*/ ,DT.COHDKEY /*CO주문번호*/ ,DT.CODTKEY /*CO주문상세번호*/ ,DT.ORDERERRCD /*주문오류 코드*/ ,DT.ORDERERRCMT /*주문생성 오류비고*/ ,DT.ICGRKEY /*상품그룹*/ ,DT.ICGRTYPE /*상품그룹유형*/ ,DT.SPEC /*규격*/ ,DT.DLVYCNTRUNIT ,DT.MALBOXQTY ,DT.MALPCSQTY ,DT.INSERTDATE /*입력 일시*/ ,DT.INSERTURKEY /*입력 사용자 ID*/ ,DT.UPDATEDATE /*수정 일시*/ ,DT.UPDATEURKEY /*수정 사용자 ID*/ FROM TORDER_INFO_SO_DT DT JOIN (
SELECT #{item.cohdkey} AS COHDKEY
SELECT TH.COHDKEY FROM ( SELECT ORGORDERKEY, CLAIMNO -- DLVYEXPCTDAY FROM TORDER_INTF_OBORDER_HD WHERE IFID = #{interfaceId} AND REQUESTDT = #{requestDt} ) TI JOIN TORDER_INFO_CO_HD TH ON (TI.ORGORDERKEY = TH.ORGORDERKEY OR TI.CLAIMNO = TH.CLAIMNO) --AND TI.DLVYEXPCTDAY = TH.DLVYEXPCTDAY AND TH.IFID = #{interfaceId} AND TH.WKSTATUS <> #{cancelWkstatus} AND TH.OWKEY = #{owkey}
) VHD ON DT.COHDKEY = VHD.COHDKEY AND DT.OWKEY = #{owkey} JOIN TORDER_INFO_SO_HD SH ON DT.OWKEY = SH.OWKEY AND DT.SOHDKEY = SH.SOHDKEY WHERE 1=1
AND DT.WKSTATUS IN
#{wkstatuses}

/* oms-ordercommon-sql-oracle.xml selectCancelDoList */ SELECT CH.COHDKEY , CH.ORGORDERKEY , CH.CLAIMNO , SH.SOHDKEY , CH.ORGORDERKEY AS MESSAGEKEY , CH.OWKEY , CH.CTKEY , IK.CNLREQRSNCD , IK.CNLREQRSNCMT FROM TORDER_INFO_CO_HD CH JOIN (
SELECT #{item.orgorderkey} AS ORGORDERKEY , #{item.claimno} AS CLAIMNO , #{item.cnlreqrsncd} AS CNLREQRSNCD , #{item.cnlreqrsncmt} AS CNLREQRSNCMT
) IK ON CH.ORGORDERKEY = IK.ORGORDERKEY AND (NULLIF(IK.CLAIMNO, '') IS NULL OR CH.CLAIMNO = IK.CLAIMNO) AND CH.EXTORDERTYPECD = CASE WHEN NULLIF(IK.CLAIMNO, '') IS NULL THEN 'DA09' ELSE 'DA10' END LEFT JOIN TORDER_INFO_SO_HD SH ON CH.OWKEY = SH.OWKEY AND CH.ORGORDERKEY = SH.ORGORDERKEY AND (NULLIF(IK.CLAIMNO, '') IS NULL OR CH.CLAIMNO = SH.CLAIMNO) AND SH.EXTORDERTYPECD = CASE WHEN NULLIF(IK.CLAIMNO, '') IS NULL THEN 'DA09' ELSE 'DA10' END
WHERE CH.OWKEY = #{owkey}

/* oms-ordercommon-sql-oracle.xml selectCancelOnlyCoList */ SELECT M.COHDKEY , M.ORGORDERKEY , SH.SOHDKEY , M.COHDKEY AS MESSAGEKEY , M.OWKEY FROM TORDER_INFO_CO_HD M JOIN (
SELECT #{item.cohdkey} AS COHDKEY
) IK ON M.COHDKEY = IK.COHDKEY LEFT JOIN TORDER_INFO_SO_HD SH ON M.OWKEY = SH.OWKEY AND M.COHDKEY = SH.COHDKEY AND SH.WKSTATUS <> #{soCancelStatus} WHERE M.OWKEY = #{owkey}

/* oms-ordercommon-sql-oracle.xml selectFrontCancelOnlyCoList */ SELECT M.COHDKEY , M.ORGORDERKEY , SH.SOHDKEY , M.COHDKEY AS MESSAGEKEY , M.OWKEY , M.CTKEY , M.ORDERTYPECD FROM TORDER_INFO_CO_HD M JOIN (
SELECT #{item.cohdkey} AS COHDKEY
) IK ON M.COHDKEY = IK.COHDKEY JOIN TORDER_INFO_SO_HD SH ON M.OWKEY = SH.OWKEY AND M.COHDKEY = SH.COHDKEY
AND SH.WKSTATUS NOT IN ('20', '40') -- 분배,완료,취소 WHERE M.OWKEY = #{owkey}

/* oms-ordercommon-sql-oracle.xml selectCancelCoList */ SELECT COALESCE(CH.COHDKEY, M.COHDKEY) AS COHDKEY , M.ORGORDERKEY , SH.SOHDKEY , COALESCE(CH.COHDKEY, M.COHDKEY) AS MESSAGEKEY , M.OWKEY , M.CTKEY , M.ORDERTYPECD FROM TORDER_INFO_CO_HD M JOIN (
SELECT #{item.cohdkey} AS COHDKEY
) IK ON M.COHDKEY = IK.COHDKEY LEFT JOIN TORDER_INFO_CO_HD CH ON M.OWKEY = CH.OWKEY AND M.ORGORDERKEY = CH.ORGORDERKEY AND CH.WKSTATUS <> #{coCancelStatus} LEFT JOIN TORDER_INFO_SO_HD SH ON CH.OWKEY = SH.OWKEY AND CH.COHDKEY = SH.COHDKEY AND SH.WKSTATUS <> #{soCancelStatus} WHERE M.OWKEY = #{owkey}

/* oms-ordercommon-sql-oracle.xml selectCancelSoList */ SELECT SH.COHDKEY , SH.ORGORDERKEY , SH.SOHDKEY , SH.SOHDKEY AS MESSAGEKEY , SH.OWKEY , SH.CTKEY , SH.ORDERTYPECD FROM TORDER_INFO_SO_HD SH JOIN (
SELECT #{item.sohdkey} AS SOHDKEY
) IK ON SH.SOHDKEY = IK.SOHDKEY WHERE SH.OWKEY = #{owkey} AND SH.WKSTATUS <> #{soCancelStatus}

/* oms-ordercommon-sql-oracle.xml selectCancelTargetList */ SELECT T.OWKEY , T.MESSAGEKEY , T.COHDKEY , T.ORGORDERKEY , T.CLAIMNO , T.SOHDKEY , T.CNLREQRSNCD , T.CNLREQRSNCMT , T.CTKEY , T.ORDERTYPECD --, COH.CNLREQRSNCD --, COH.CNLREQRSNCMT , COALESCE(T.WKSTATUS, #{soCancelStatus}) AS SO_WKSTATUS , CASE WHEN CO_NOTCANCELCNT=0 AND SO_NOTCANCELCNT=0 THEN 'Y' ELSE 'N' END AS CANCEL_YN , CASE WHEN CO_NOTCANCELCNT > 0 THEN #{coErrorCode} WHEN SO_NOTCANCELCNT > 0 THEN #{soErrorCode} ELSE #{successCode} END AS ERROR_CODE , CASE WHEN CO_NOTCANCELCNT=0 THEN 'Y' ELSE 'N' END AS CO_CANCEL_YN , CASE WHEN CO_NOTCANCELCNT > 0 THEN #{coErrorCode} ELSE #{successCode} END AS CO_ERROR_CODE , CASE WHEN SO_NOTCANCELCNT=0 THEN 'Y' ELSE 'N' END AS SO_CANCEL_YN , CASE WHEN SO_NOTCANCELCNT > 0 THEN #{soErrorCode} ELSE #{successCode} END AS SO_ERROR_CODE , COALESCE(T.BATWKSTATUS, 'FAIL') AS BATWKSTATUS FROM ( SELECT T.OWKEY , T.MESSAGEKEY , T.COHDKEY , T.ORGORDERKEY , T.CLAIMNO , T.SOHDKEY , T.CNLREQRSNCD , T.CNLREQRSNCMT , T.WKSTATUS , MAX(T.CTKEY) AS CTKEY , MAX(T.ORDERTYPECD) AS ORDERTYPECD , SUM(CASE WHEN T.CO_OWKEY IS NOT NULL AND COS.WKSTATUS IS NULL THEN 1 ELSE 0 END) AS CO_NOTCANCELCNT , SUM(CASE WHEN T.SO_OWKEY IS NOT NULL AND SOS.WKSTATUS IS NULL THEN 1 ELSE 0 END) AS SO_NOTCANCELCNT , T.BATWKSTATUS FROM ( SELECT IKK.OWKEY , IKK.MESSAGEKEY , IKK.COHDKEY , IKK.ORGORDERKEY , IKK.CLAIMNO , IKK.SOHDKEY , IKK.CNLREQRSNCD , IKK.CNLREQRSNCMT , MAX(IKK.CTKEY) AS CTKEY , MAX(IKK.ORDERTYPECD) AS ORDERTYPECD , MAX(IKK.CO_OWKEY) AS CO_OWKEY , MAX(IKK.SO_OWKEY) AS SO_OWKEY , MAX(IKK.WKSTATUS) AS WKSTATUS , MAX(IKK.SO_WKSTATUS) AS SO_WKSTATUS , MAX(IKK.CO_WKSTATUS) AS CO_WKSTATUS , MAX(IKK.BATWKSTATUS) AS BATWKSTATUS FROM ( SELECT IK.OWKEY , IK.MESSAGEKEY , IK.COHDKEY , IK.ORGORDERKEY , IK.CLAIMNO , IK.SOHDKEY , IK.CNLREQRSNCD , IK.CNLREQRSNCMT , CH.CTKEY , CH.ORDERTYPECD , CH.OWKEY AS CO_OWKEY , NULL AS SO_OWKEY , NULL AS WKSTATUS , NULL AS SO_WKSTATUS
, CD.WKSTATUS AS CO_WKSTATUS -- coCreateStatus:RECEIPT , SH.BATWKSTATUS FROM (
SELECT #{item.orgorderkey} AS ORGORDERKEY , #{item.claimno} AS CLAIMNO , #{item.cohdkey} AS COHDKEY , #{item.sohdkey} AS SOHDKEY , #{item.messagekey} AS MESSAGEKEY , #{item.owkey} AS OWKEY , #{item.cnlreqrsncd} AS CNLREQRSNCD , #{item.cnlreqrsncmt} AS CNLREQRSNCMT
) IK LEFT JOIN TORDER_INFO_CO_HD CH ON IK.OWKEY = CH.OWKEY AND IK.COHDKEY = CH.COHDKEY LEFT JOIN TORDER_INFO_CO_DT CD ON IK.OWKEY = CD.OWKEY AND IK.COHDKEY = CD.COHDKEY LEFT JOIN TORDER_INFO_SO_HD SH ON CH.OWKEY = SH.OWKEY AND CH.COHDKEY = SH.COHDKEY LEFT JOIN TORDER_INFO_SO_DT SD ON CD.OWKEY = SD.OWKEY AND CD.COHDKEY = SD.COHDKEY AND CD.CODTKEY = SD.CODTKEY UNION ALL SELECT IK.OWKEY , IK.MESSAGEKEY , IK.COHDKEY , IK.ORGORDERKEY , IK.CLAIMNO , IK.SOHDKEY , IK.CNLREQRSNCD , IK.CNLREQRSNCMT , SH.CTKEY , SH.ORDERTYPECD , NULL AS CO_OWKEY , SH.OWKEY AS SO_OWKEY
, SH.WKSTATUS AS WKSTATUS -- soCreateStatus:00 , SD.WKSTATUS AS SO_WKSTATUS -- soCreateStatus:00 , NULL AS CO_WKSTATUS , SH.BATWKSTATUS FROM (
SELECT #{item.orgorderkey} AS ORGORDERKEY , #{item.claimno} AS CLAIMNO , #{item.cohdkey} AS COHDKEY , #{item.sohdkey} AS SOHDKEY , #{item.messagekey} AS MESSAGEKEY , #{item.owkey} AS OWKEY , #{item.cnlreqrsncd} AS CNLREQRSNCD , #{item.cnlreqrsncmt} AS CNLREQRSNCMT
) IK LEFT JOIN TORDER_INFO_SO_HD SH ON IK.OWKEY = SH.OWKEY AND IK.SOHDKEY = SH.SOHDKEY LEFT JOIN TORDER_INFO_SO_DT SD ON IK.OWKEY = SD.OWKEY AND IK.SOHDKEY = SD.SOHDKEY ) IKK GROUP BY IKK.OWKEY , IKK.MESSAGEKEY , IKK.COHDKEY , IKK.ORGORDERKEY , IKK.CLAIMNO , IKK.SOHDKEY , IKK.CNLREQRSNCD , IKK.CNLREQRSNCMT ) T LEFT JOIN (
SELECT #{item} AS WKSTATUS
) COS ON T.CO_WKSTATUS = COS.WKSTATUS LEFT JOIN (
SELECT #{item} AS WKSTATUS
) SOS ON T.SO_WKSTATUS = SOS.WKSTATUS GROUP BY T.OWKEY , T.MESSAGEKEY , T.COHDKEY , T.ORGORDERKEY , T.CLAIMNO , T.SOHDKEY , T.CNLREQRSNCD , T.CNLREQRSNCMT , T.WKSTATUS , T.BATWKSTATUS ) T LEFT JOIN TORDER_INFO_CO_HD COH ON T.OWKEY = COH.OWKEY AND T.COHDKEY = COH.COHDKEY

/* oms-ordercommon-sql-oracle.xml selectCancelEoTarget */ SELECT T.OWKEY , T.MESSAGEKEY , T.CNLREQRSNCD , T.CNLREQRSNCMT , T.COHDKEY , T.ORGORDERKEY , T.SOHDKEY , CASE WHEN CO_NOTCANCELCNT=0 AND SO_NOTCANCELCNT=0 THEN 'Y' ELSE 'N' END AS CANCEL_YN , CASE WHEN CO_NOTCANCELCNT>0 OR SO_NOTCANCELCNT>0 THEN #{wmErrorCode} ELSE #{successCode} END AS ERROR_CODE FROM ( SELECT SH.OWKEY , IK.MESSAGEKEY , IK.CNLREQRSNCD , IK.CNLREQRSNCMT , SH.COHDKEY , SH.ORGORDERKEY , SH.SOHDKEY , SUM(CASE WHEN CH.WKSTATUS IS NULL THEN 1 ELSE 0 END) AS CO_NOTCANCELCNT , SUM(CASE WHEN SH.WKSTATUS IS NULL THEN 1 ELSE 0 END) AS SO_NOTCANCELCNT FROM TORDER_INFO_SO_HD SH JOIN (
SELECT #{item.orgorderkey} AS ORGORDERKEY , #{item.cnlreqrsncd} AS CNLREQRSNCD , #{item.cnlreqrsncmt} AS CNLREQRSNCMT , #{item.cohdkey} AS COHDKEY , #{item.sohdkey} AS SOHDKEY , #{item.messagekey} AS MESSAGEKEY , #{item.owkey} AS OWKEY
) IK ON SH.SOHDKEY = IK.SOHDKEY LEFT JOIN TORDER_INFO_CO_HD CH ON IK.OWKEY = CH.OWKEY AND IK.COHDKEY = CH.COHDKEY LEFT JOIN TORDER_INFO_CO_DT CD ON IK.OWKEY = CD.OWKEY AND IK.COHDKEY = CD.COHDKEY LEFT JOIN TORDER_INFO_SO_DT SD ON CD.OWKEY = SD.OWKEY AND CD.COHDKEY = SD.COHDKEY AND CD.CODTKEY = SD.CODTKEY WHERE SH.OWKEY = #{owkey} GROUP BY SH.OWKEY , IK.MESSAGEKEY , IK.CNLREQRSNCD , IK.CNLREQRSNCMT , SH.COHDKEY , SH.ORGORDERKEY , SH.SOHDKEY ) T

