/* oms-ordercommon-sql-oracle.xml updateWmObInvInit */ UPDATE TWORK_INFO_IVATXLCXULC IVAT SET AVQTY = IVAT.AVQTY + AL.ALQTY , ALQTY = IVAT.ALQTY - AL.ALQTY FROM ( SELECT AL.CTKEY , AL.OWKEY , AL.ICKEY , AL.LCKEY , AL.IVATKEY , AL.ULCKEY , SUM(COALESCE(AL.ALQTY, 0)) AS ALQTY FROM TWORK_INFO_OB_HD OB JOIN TWORK_INFO_AL_DT AL ON OB.CTKEY = AL.CTKEY AND OB.OWKEY = AL.OWKEY AND OB.OBHDKEY = AL.OBHDKEY WHERE OB.ORHDKEY IN (
SELECT #{item.soHdkey} AS SO_HDKEY
) GROUP BY AL.CTKEY , AL.OWKEY , AL.ICKEY , AL.LCKEY , AL.IVATKEY , AL.ULCKEY ) AL WHERE IVAT.CTKEY = AL.CTKEY AND IVAT.OWKEY = AL.OWKEY AND IVAT.ICKEY = AL.ICKEY AND IVAT.LCKEY = AL.LCKEY AND IVAT.IVATKEY = AL.IVATKEY AND IVAT.ULCKEY = AL.ULCKEY

