		     , UPDATEDATE = #{interfaceDate}
             , UPDATEURKEY = #{interfaceUrkey}
		 WHERE T.OWKEY = #{owkey}
		   AND EXISTS ( 
						SELECT 1
					      FROM (

						        SELECT #{item.soHdkey} AS SO_HDKEY 

					       	   ) ORD  
					     WHERE ORD.SO_HDKEY = T.ORHDKEY
					   )

