/* oms-ordercommon-sql-oracle.xml updateCoHdRsnInfo */
UPDATE TORDER_INFO_CO_HD T 
   SET CNLREQRSNCD = #{cnlreqrsncd}
	 , CNLREQRSNCMT = #{cnlreqrsncmt}
 WHERE T.OWKEY = #{owkey}
   AND EXISTS ( 
				SELECT 1
			      FROM (
				        SELECT #{cohdkey} AS COHDKEY 
