		WHERE OWKEY = #{owkey}
		AND   COHDKEY = #{cohdkey}

		/* oms-ordercommon-sql-oracle.xml updateCOWksatusInitDt */
		UPDATE TORDER_INFO_CO_DT SET WKSTATUS = #{wkstatus}
                           , UPDATEDATE = #{interfaceDate}
                           , UPDATEURKEY = #{interfaceUrkey}
		WHERE OWKEY = #{owkey}
		AND   COHDKEY = #{cohdkey}

