/* oms-ordercommon-sql-oracle.xml insertCoCancelResult */ INSERT INTO TORDER_BATCH_CANCEL_RESULT ( OWKEY /*화주*/ , ORGORDERKEY /*외부키*/ , COHDKEY , REGDT /*등록일자*/ , PRCSYN /*처리여부*/ , PRCSDATE /*처리일시*/ , BATEXECID /*배치 실행ID*/ , INSERTDATE /*입력 일시*/ , INSERTURKEY /*입력 사용자 ID*/ , UPDATEDATE /*수정 일시*/ , UPDATEURKEY /*수정 사용자 ID*/ ) SELECT TT.OWKEY , TT.ORGORDERKEY , TT.COHDKEY , SUBSTR(#{interfaceDate}, 1, 8) AS REGDT /*등록일자*/ , 'N' AS PRCSYN /*처리여부*/ , NULL AS PRCSDATE /*처리일시*/ , NULL AS BATEXECID /*배치 실행ID*/ , #{interfaceDate} AS INSERTDATE /*입력 일시*/ , #{interfaceUrkey} AS INSERTURKEY /*입력 사용자 ID*/ , #{interfaceDate} AS UPDATEDATE /*수정 일시*/ , #{interfaceUrkey} AS UPDATEURKEY /*수정 사용자 ID*/ FROM ( SELECT CH.OWKEY , CH.ORGORDERKEY , ORD.COHDKEY , CASE WHEN CR.BATCHKEY IS NULL THEN 'Y' ELSE 'N' END AS SAVEYN FROM (
SELECT #{item.cohdkey} AS COHDKEY
) ORD JOIN TORDER_INFO_CO_HD CH ON ORD.COHDKEY = CH.COHDKEY AND CH.OWKEY = #{owkey} JOIN TORDER_INFO_ORTYPE_MAPPING OM ON CH.OWKEY = OM.OWKEY AND CH.EXTORDERTYPECD = OM.EXTORDERTYPECD AND CH.ORDERTYPECD = OM.ORDERTYPECD AND OM.DELYN = 'N' LEFT JOIN TORDER_BATCH_CANCEL_RESULT CR ON CH.OWKEY = CR.OWKEY AND CH.ORGORDERKEY = CR.ORGORDERKEY AND CH.COHDKEY = CR.COHDKEY AND CR.PRCSYN = 'N' WHERE 1 = 1 --ADN OM.TRANYN = 'Y' /*SAP전송대상여부*/ AND CH.ORGORDERKEY IS NOT NULL AND COALESCE(CH.SPLITORDERYN, 'N')<>'Y' ) TT WHERE TT.SAVEYN = 'Y'

