/* oms-ordercommon-sql-oracle.xml - insertInOutCloseOmsPerformance */ INSERT INTO TORDER_INFO_WMS_PERFORMANCE ( OWKEY , CTKEY , SOHDKEY , SODTKEY , EXPCTQTY , CNFRMQTY , ICKEY , UOM , CNFRMDATE , CLOSEYN , ORGORDERKEY , ORGORDERDTKEY , NISYN , NISCNLRNGDIV , DLVRYCORPCD , WBLNO , CLAIMNO , RIRSNCD , CMT , AVQTY , NAVQTY , REPROCESSYN , EXPIREDATE , DELIVERYPERSONID , WORKSEQ , IFID , INSERTDATE , INSERTURKEY , UPDATEDATE , UPDATEURKEY ) SELECT INTF.OWKEY , INTF.CTKEY , INTF.SOHDKEY , INTF.SODTKEY , INTF.EXPCTQTY , INTF.CNFRMQTY , INTF.ICKEY , INTF.UOM , INTF.CNFRMDATE , INTF.CLOSEYN , INTF.ORGORDERKEY , INTF.ORGORDERDTKEY , CASE WHEN INTF.NISCNLRNGDIV IN ('03', '07') THEN 'Y' WHEN COALESCE(INTF.EXPCTQTY, 0)-COALESCE(INTF.CNFRMQTY, 0)>0 THEN 'Y' ELSE 'N' END AS NISYN , CASE WHEN INTF.NISCNLRNGDIV IS NULL AND COALESCE(INTF.EXPCTQTY, 0)-COALESCE(INTF.CNFRMQTY, 0)>0 THEN '03' ELSE INTF.NISCNLRNGDIV END AS NISCNLRNGDIV , INTF.DLVRYCORPCD , INTF.WBLNO , INTF.CLAIMNO , INTF.RIRSNCD , INTF.CMT , INTF.AVQTY , INTF.NAVQTY , INTF.REPROCESSYN , INTF.EXPIREDATE , INTF.DELIVERYPERSONID , COALESCE(Z.WORKSEQ, 0) + ROW_NUMBER() OVER(PARTITION BY INTF.OWKEY, INTF.SOHDKEY, INTF.SODTKEY ORDER BY INTF.INTERFACEKEY) AS WORKSEQ , INTF.IFID , TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS') , #{interfaceUrkey} , TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS') , #{interfaceUrkey} FROM TORDER_INTF_WMS_PERFORMANCE INTF LEFT OUTER JOIN ( SELECT A.OWKEY , A.SOHDKEY , A.SODTKEY , MAX(A.WORKSEQ) AS WORKSEQ FROM TORDER_INFO_WMS_PERFORMANCE A WHERE EXISTS ( SELECT 1 FROM (
SELECT #{item.owkey} AS OWKEY , #{item.sohdkey} AS SOHDKEY , #{item.sodtkey} AS SODTKEY
) B WHERE B.OWKEY = A.OWKEY AND B.SOHDKEY = A.SOHDKEY AND B.SODTKEY = A.SODTKEY ) GROUP BY A.OWKEY, A.SOHDKEY, A.SODTKEY ) Z ON INTF.OWKEY = Z.OWKEY AND INTF.SOHDKEY = Z.SOHDKEY AND INTF.SODTKEY = Z.SODTKEY WHERE 1 = 1 AND INTF.IFID = #{ifid} AND EXISTS ( SELECT 1 FROM (
SELECT #{item.owkey} AS OWKEY , #{item.sohdkey} AS SOHDKEY , #{item.sodtkey} AS SODTKEY
) B WHERE B.OWKEY = INTF.OWKEY AND B.SOHDKEY = INTF.SOHDKEY AND B.SODTKEY = INTF.SODTKEY )

