/* oms-ordercommon-sql-oracle.xml - insertInRtnCloseOmsPerformance */ INSERT INTO TORDER_INFO_WMS_PERFORMANCE ( OWKEY , CTKEY , SOHDKEY , SODTKEY , EXPCTQTY , CNFRMQTY , AVQTY , NAVQTY , NORMALQTY , DMGQTY , DFCQTY , DONAQTY , FOODDMGQTY , MISOBQTY , ICKEY , UOM , CNFRMDATE , WORKSEQ , IFID , INSERTDATE , INSERTURKEY , UPDATEDATE , UPDATEURKEY ) SELECT INTF.OWKEY , INTF.CTKEY , INTF.SOHDKEY , INTF.SODTKEY , C.EXPCTQTY , SUM(INTF.CNFRMQTY) AS CNFRMQTY , SUM(INTF.AVQTY) AS AVQTY , SUM(INTF.NAVQTY) AS NAVQTY , SUM(INTF.NORMALQTY) AS NORMALQTY , SUM(INTF.DMGQTY) AS DMGQTY , SUM(INTF.DFCQTY) AS DFCQTY , SUM(INTF.DONAQTY) AS DONAQTY , SUM(INTF.FOODDMGQTY) AS FOODDMGQTY , SUM(INTF.MISOBQTY) AS MISOBQTY , INTF.ICKEY , 'EA' AS UOM , TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS') AS CNFRMDATE , COALESCE(Z.WORKSEQ, 0) + ROW_NUMBER() OVER(PARTITION BY INTF.OWKEY, INTF.SOHDKEY, INTF.SODTKEY ORDER BY INTF.ickey) AS WORKSEQ , INTF.IFID , TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS') AS INSERTDATE , 'I/F Recv.Inbound' AS INSERTURKEY , TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS') AS UPDATEDATE , 'I/F Recv.Inbound' AS UPDATEURKEY FROM TORDER_INTF_WMS_PERFORMANCE INTF JOIN TORDER_INFO_SO_DT C ON INTF.OWKEY = C.OWKEY AND INTF.SOHDKEY = C.SOHDKEY AND INTF.SODTKEY = C.SODTKEY LEFT OUTER JOIN ( SELECT A.OWKEY , A.SOHDKEY , A.SODTKEY , MAX(A.WORKSEQ) AS WORKSEQ FROM TORDER_INFO_WMS_PERFORMANCE A WHERE EXISTS ( SELECT 1 FROM (
SELECT #{item.owkey} AS OWKEY , #{item.sohdkey} AS SOHDKEY , #{item.sodtkey} AS SODTKEY
) B WHERE B.OWKEY = A.OWKEY AND B.SOHDKEY = A.SOHDKEY AND B.SODTKEY = A.SODTKEY ) GROUP BY A.OWKEY, A.SOHDKEY, A.SODTKEY ) Z ON INTF.OWKEY = Z.OWKEY AND INTF.SOHDKEY = Z.SOHDKEY AND INTF.SODTKEY = Z.SODTKEY WHERE 1 = 1 AND INTF.IFID = #{ifid} AND EXISTS ( SELECT 1 FROM (
SELECT #{item.owkey} AS OWKEY , #{item.sohdkey} AS SOHDKEY , #{item.sodtkey} AS SODTKEY
) B WHERE B.OWKEY = INTF.OWKEY AND B.SOHDKEY = INTF.SOHDKEY AND B.SODTKEY = INTF.SODTKEY ) GROUP BY INTF.OWKEY , INTF.CTKEY , INTF.SOHDKEY , INTF.SODTKEY , INTF.ICKEY , INTF.IFID , Z.WORKSEQ , C.EXPCTQTY

/* oms-ordercommon-sql-oracle.xml insertIntfErpTableIbClose */ INSERT INTO TORDER_EAI_IBPERFORMANCE_BATCH ( SND_NO , SND_ROW , SND_TOT_ROW , SND_DATE , SND_DT , SND_TRSN_TYP , SND_PROC_TYP , WRKCTKEY , REQORDERNO , OBNO , ICKEY , IBCNFRMQTY , IBCNFRMDAY , SOHDKEY , SODTKEY ) SELECT #{ifid} AS SND_NO , ROW_NUMBER() OVER() AS SND_ROW , COUNT(*) OVER() AS SND_TOT_ROW , #{sysdate} AS SND_DATE , CURRENT_TIMESTAMP AS SND_DT , 'I' AS SND_TRSN_TYP , 'N' AS SND_PROC_TYP , T.CTKEY AS WRKCTKEY , T.REQORDERNO , EAI.B2BOBNO AS OBNO , T.ICKEY , T.CNFRMQTY AS IBCNFRMQTY , TO_CHAR(TO_DATE(T.CNFRMDATE, 'YYYYMMDDHH24MISS'), 'YYYYMMDD') AS IBCNFRMDAY , T.SOHDKEY , T.SODTKEY FROM (
SELECT #{item.owkey} AS OWKEY, #{item.sohdkey} AS SOHDKEY, #{item.sodtkey} AS SODTKEY, #{item.ctkey} AS CTKEY, #{item.ickey} AS ICKEY, #{item.reqorderno} AS REQORDERNO, #{item.shmistno} AS SHMISTNO, #{item.cnfrmdate} AS CNFRMDATE, #{item.extordertypecd} AS EXTORDERTYPECD, #{item.cohdkey} AS COHDKEY, #{item.codtkey} AS CODTKEY, #{item.nisyn} AS NISYN, #{item.niscnlrngdiv} AS NISCNLRNGDIV, #{item.erpperfmansyn} AS ERPPERFMANSYN, #{item.malperfmansyn} AS MALPERFMANSYN, #{item.ordexpctqty} AS ORDEXPCTQTY, #{item.expctqty} AS EXPCTQTY, #{item.cnfrmqty} AS CNFRMQTY, #{item.wkstatus} AS WKSTATUS
) T LEFT OUTER JOIN ( SELECT REQORDERNO ,SHMISTNO ,B2BOBNO ,B2BOBCNFRMDAY ,FROMCTKEY ,TOCTKEY ,REQORDERTYPE ,ICKEY ,COALESCE(MAX(B2BOBQTY), 0) AS B2BOBQTY FROM TORDER_INFO_B2B_ORDER WHERE 1 = 1 GROUP BY REQORDERNO ,SHMISTNO ,B2BOBNO ,B2BOBCNFRMDAY ,FROMCTKEY ,TOCTKEY ,REQORDERTYPE ,ICKEY ) EAI ON T.REQORDERNO = EAI.REQORDERNO AND T.ICKEY = EAI.ICKEY WHERE 1 = 1 AND NOT EXISTS ( SELECT 1 FROM TORDER_EAI_IBPERFORMANCE_BATCH WHERE SOHDKEY = T.SOHDKEY AND SODTKEY = T.SODTKEY )

