/* oms-ordercommon-sql-oracle.xml selectInOutCloseSendYn */
SELECT 
    CASE 
        WHEN COALESCE((
				 SELECT SUM(COALESCE(SD.EXPCTQTY, 0))
                   FROM TORDER_INFO_SO_HD SH
                   JOIN TORDER_INFO_SO_DT SD
                     ON SH.OWKEY = SD.OWKEY
                    AND SH.SOHDKEY = SD.SOHDKEY
                  WHERE SH.SOHDKEY = #{sohdkey}
                    AND SH.OWKEY = #{owkey}
                )
              -
                (
				 SELECT SUM(COALESCE(EXPCTQTY, 0))
                 FROM TORDER_INFO_WMS_PERFORMANCE
                 WHERE OWKEY = #{owkey}
                 AND SOHDKEY = #{sohdkey}
                ), -1) = 0
         AND (
			  SELECT COALESCE(OM.ERPPERFMANSYN, 'N')
              FROM TORDER_INFO_SO_HD SH
              JOIN TORDER_INFO_ORTYPE_MAPPING OM
              ON SH.OWKEY = OM.OWKEY
              AND SH.EXTORDERTYPECD = OM.EXTORDERTYPECD
              AND SH.ORDERTYPECD = OM.ORDERTYPECD
              WHERE SH.OWKEY = #{owkey}
                AND SH.SOHDKEY = #{sohdkey}
                AND OM.DELYN = 'N'
             ) = 'Y'
        THEN 'Y'
        ELSE 'N'
    END AS SENDYN

/* oms-ordercommon-sql-oracle.xml selectSrchKeyInfo */
SELECT SH.COHDKEY
FROM TORDER_INFO_SO_HD SH
WHERE 1 = 1
AND SH.OWKEY = #{owkey}
AND SH.EXTORDERTYPECD = #{extordertypecd}
AND SH.SOHDKEY = #{sohdkey}

mapper.insert:
	/* oms-ordercommon-sql-oracle.xml updateIntfWmsPerformance */
	UPDATE TORDER_INTF_WMS_PERFORMANCE SET
	  CLOSEYN = 'Y'
	, UPDATEDATE = TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
    , UPDATEURKEY = #{interfaceUrkey}
	WHERE 1 = 1
	AND IFID = #{ifid}
	and SOHDKEY = #{sohdkey}

	/* oms-ordercommon-sql-oracle.xml updateInfofWmsRtnPerformance */
	UPDATE TORDER_INFO_WMS_PERFORMANCE SET
	  CLOSEYN = 'Y'
	, ERPSENDYN = 'Y'
	, NISYN = #{nisyn}
	, UPDATEDATE = TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
    , UPDATEURKEY = #{interfaceUrkey}
	WHERE 1 = 1
	AND SOHDKEY = #{sohdkey}
	AND SODTKEY = #{sodtkey}
	AND WORKSEQ = #{workseq}

	/* oms-ordercommon-sql-oracle.xml updateInfofCloseWmsRtnPerformance */
	UPDATE TORDER_INFO_WMS_PERFORMANCE SET
	  CLOSEYN = 'Y'
	, NISYN = #{nisyn}
	, UPDATEDATE = TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
    , UPDATEURKEY = #{interfaceUrkey}
	WHERE 1 = 1
	AND SOHDKEY = #{sohdkey}
	AND SODTKEY = #{sodtkey}
	AND WORKSEQ = #{workseq}

	/* oms-ordercommon-sql-oracle.xml updateInfoSoDtRtnPerformance */
	UPDATE TORDER_INFO_SO_DT SET
	  WKSTATUS = #{soWkstatus}
	, CNFRMQTY = #{cnfrmqty}
	, SNDQTY = #{cnfrmqty}
	, NISYN = #{nisyn}

	, NISQTY = EXPCTQTY - #{cnfrmqty}

	, UPDATEDATE = TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
    , UPDATEURKEY = #{interfaceUrkey}
	WHERE 1 = 1
	AND SOHDKEY = #{sohdkey}
	AND SODTKEY = #{sodtkey}

	/* oms-ordercommon-sql-oracle.xml updateInfoSoHdRtnPerformance */
	UPDATE TORDER_INFO_SO_HD SH SET
	  SH.WKSTATUS = #{soWkstatus}
	, SH.NISYN = #{nisyn}
	, SH.NISCNLRNGDIV = #{niscnlrngdiv}
	, SH.CNFRMDAY = TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDD')
	, SH.UPDATEDATE = TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
    , SH.UPDATEURKEY = #{interfaceUrkey}
	WHERE 1 = 1
	AND SH.SOHDKEY = #{sohdkey}
	AND NOT EXISTS (
				    SELECT 1
				    FROM TORDER_INFO_SO_DT SD
				    WHERE SD.SOHDKEY = SH.SOHDKEY
				      AND SD.WKSTATUS <> #{soWkstatus}
			      )

		/* oms-ordercommon-sql-oracle.xml updateInfoCoDtRtnPerformance */
		UPDATE TORDER_INFO_CO_DT SET
		  WKSTATUS = #{coWkstatus}
		, UPDATEDATE = TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
	    , UPDATEURKEY = #{interfaceUrkey}
		WHERE 1 = 1
		AND COHDKEY = #{cohdkey}
  		AND CODTKEY = (
						SELECT X.CODTKEY 
						FROM TORDER_INFO_SO_DT X 
						WHERE X.SOHDKEY = #{sohdkey} 
						AND X.SODTKEY = #{sodtkey} 
						AND X.WKSTATUS = #{soWkstatus}
					  )

	/* oms-ordercommon-sql-oracle.xml updateInfoCoHdRtnPerformance */
	UPDATE TORDER_INFO_CO_HD SET
	  ERPSNDFAILYN = 'N'
	, ERPSNDSEQ = #{workseq}
	, FAILCNT = #{failcnt}
	, ERPRESPONSECD = #{erpresponsecd}
	, WKSTATUS = #{coWkstatus}
	, NISYN = #{nisyn}
	, NISCNLRNGDIV = #{niscnlrngdiv}
	, UPDATEDATE = TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
    , UPDATEURKEY = #{interfaceUrkey}
	WHERE 1 = 1
	AND COHDKEY = (
					SELECT X.COHDKEY 
					FROM TORDER_INFO_SO_HD X 
					WHERE X.SOHDKEY = #{sohdkey} 
					AND X.WKSTATUS = #{soWkstatus}
				  )

		/* oms-ordercommon-sql-oracle.xml updateWmsPerformance */
		UPDATE TORDER_INFO_WMS_PERFORMANCE SET
		  CLOSEYN = 'Y'
		, ERPSENDYN = #{erpsendyn}
		, NISYN = #{nisyn}
		, UPDATEDATE = TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
	    , UPDATEURKEY = #{interfaceUrkey}
		WHERE OWKEY = #{owkey}
        AND SOHDKEY = #{sohdkey}
        AND SODTKEY = #{sodtkey}

/* oms-ordercommon-sql-oracle.xml updateSoDtPerformance */
UPDATE TORDER_INFO_SO_DT SET
  WKSTATUS = #{soCompleteWkstatus}
, CNFRMQTY = #{cnfrmqty}
, SNDQTY = CASE WHEN #{sendyn}='Y' AND #{erpsendyn}='Y' THEN #{cnfrmqty} ELSE SNDQTY END
, NISYN = #{nisyn}

, NISQTY = INITQTY - #{cnfrmqty}

, UPDATEDATE = TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
, UPDATEURKEY = #{interfaceUrkey}
WHERE OWKEY = #{owkey}
AND SOHDKEY = #{sohdkey}
AND SODTKEY = #{sodtkey}

/* oms-ordercommon-sql-oracle.xml updateCoDtPerformance */
UPDATE TORDER_INFO_CO_DT SET
  WKSTATUS = CASE WHEN #{sendyn}='Y' AND #{erpsendyn}='Y' THEN #{coSendWkstatus} 
  				  ELSE #{coCompleteWkstatus} 
  			 END
, UPDATEDATE = TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
, UPDATEURKEY = #{interfaceUrkey}
WHERE OWKEY = #{owkey}
AND COHDKEY = #{cohdkey}
AND CODTKEY = #{codtkey}

        /* oms-ordercommon-sql-oracle.xml updateSoHdPerformance */
        UPDATE TORDER_INFO_SO_HD SET
          WKSTATUS = #{soCompleteWkstatus}
        , NISYN = CASE WHEN (SELECT SUM(CASE WHEN COALESCE(NISYN, 'N')='Y' THEN 1 ELSE 0 END)
				               FROM TORDER_INFO_SO_DT
				              WHERE OWKEY = #{owkey}
				                AND SOHDKEY = #{sohdkey}
				             ) > 0 THEN 'Y' 
				       ELSE 'N'
				  END
        , NISCNLRNGDIV = #{niscnlrngdiv}
        , CNFRMDAY = CASE WHEN #{sendyn}='Y' THEN TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDD') ELSE CNFRMDAY END 
        , UPDATEDATE = TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
        , UPDATEURKEY = #{interfaceUrkey}
        WHERE OWKEY = #{owkey}
        AND SOHDKEY = #{sohdkey}
        AND (SELECT CASE WHEN SUM(CASE WHEN WKSTATUS=#{soCompleteWkstatus} THEN 1 ELSE 0 END) = COUNT(1) THEN 'Y' ELSE 'N' END
               FROM TORDER_INFO_SO_DT
              WHERE OWKEY = #{owkey}
                AND SOHDKEY = #{sohdkey}
            ) = 'Y'

        /* oms-ordercommon-sql-oracle.xml updateCoHdPerformance */
        UPDATE TORDER_INFO_CO_HD SET
          WKSTATUS = CASE WHEN #{sendyn}='Y' AND #{erpsendyn}='Y' THEN #{coSendWkstatus} ELSE #{coCompleteWkstatus} END

	        , ERPSNDFAILYN = CASE WHEN #{erpsendyn}='Y' THEN 'N' ELSE 'Y' END
			, FAILCNT = CASE WHEN #{erpsendyn}='Y' THEN FAILCNT ELSE COALESCE(FAILCNT, 0)+1 END
			, ERPRESPONSECD = #{erpresponsecd}

        , NISYN = #{nisyn}
        , NISCNLRNGDIV = #{niscnlrngdiv}
        , UPDATEDATE = TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
        , UPDATEURKEY = #{interfaceUrkey}
        WHERE OWKEY = #{owkey}
        AND COHDKEY = #{cohdkey}
        AND (SELECT CASE WHEN SUM(CASE WHEN WKSTATUS=(CASE WHEN #{sendyn}='Y' AND #{erpsendyn}='Y' THEN #{coSendWkstatus} 
        												   ELSE #{coCompleteWkstatus} 
        										      END) THEN 1 
        							   ELSE 0 END)
									= COUNT(1) THEN 'Y' 
        			ELSE 'N' 
        			END
               FROM TORDER_INFO_CO_DT
              WHERE OWKEY = #{owkey}
                AND COHDKEY = #{cohdkey}
            ) = 'Y'

