	/* oms-ordercommon-sql-oracle.xml updateSoHdRtnCnl */
	UPDATE TORDER_INFO_SO_HD SET
	  WKSTATUS = #{soWkstatus}
	, UPDATEDATE = TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
    , UPDATEURKEY = #{interfaceUrkey}
	WHERE 1 = 1
	AND SOHDKEY = #{sohdkey}

	/* oms-ordercommon-sql-oracle.xml updateCoDtRtnCnl */
	UPDATE TORDER_INFO_CO_DT SET
	  WKSTATUS = #{coWkstatus}
	, UPDATEDATE = TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
    , UPDATEURKEY = #{interfaceUrkey}
	WHERE 1 = 1
	AND COHDKEY = #{cohdkey}

	/* oms-ordercommon-sql-oracle.xml updateCoHdRtnCnl */
	UPDATE TORDER_INFO_CO_HD SET
	  WKSTATUS = #{coWkstatus}
	, UPDATEDATE = TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
    , UPDATEURKEY = #{interfaceUrkey}
	WHERE 1 = 1
	AND COHDKEY = #{cohdkey}

mapper.select:
		/* oms-ordercommon-sql-oracle.xml selectCtkeyValidCheck */
        SELECT COUNT(1)
        FROM TORDER_MST_CT
        WHERE CTKEY = #{ctkey}
          AND MANAGEMENTYN = 'Y'

	/* oms-ordercommon-sql-oracle.xml selectOlnickeyValidCheck */
    SELECT COUNT(1)
    FROM TORDER_MST_IC
    WHERE ICKEY = #{olnickey}
      AND DELYN = 'N'

	/* oms-ordercommon-sql-oracle.xml selectClaimnoValidCheck */
    SELECT COUNT(1)
    FROM TORDER_INFO_CO_HD
    WHERE CLAIMNO = #{claimno}

	/* oms-ordercommon-sql-oracle.xml selectOrgorderkeyValidCheck */
    SELECT COUNT(1)
    FROM TORDER_INFO_CO_HD
    WHERE ORGORDERKEY = #{orgorderkey}

    SELECT COUNT(1)
    FROM TORDER_INFO_CO_HD
    WHERE 1 = 1
      AND OWKEY = #{owkey}
      AND ORGORDERKEY = #{orgorderkey}
      AND CLAIMNO = #{claimno}

	  AND EXTORDERTYPECD = #{extordertypecd}

mapper.update:
		/* oms-ordercommon-sql-oracle.xm updateSoHdShmistno */
		UPDATE TORDER_INFO_SO_HD
		   SET SHMISTNO = #{shmistno}
             , UPDATEDATE = #{updatedate}
             , UPDATEURKEY = #{updateurkey}
		 WHERE OWKEY = #{owkey}
		   AND SOHDKEY = #{sohdkey}

		/* oms-ordercommon-sql-oracle.xm updateCoHdShmistno */
		UPDATE TORDER_INFO_CO_HD 
		   SET SHMISTNO = #{shmistno}
             , UPDATEDATE = #{updatedate}
             , UPDATEURKEY = #{updateurkey}
		 WHERE OWKEY = #{owkey}
		   AND COHDKEY = #{cohdkey}

mapper.insert:
/* oms-ordercommon-sql-oracle.xml - insertIntfStockCloseWmsToOms */
INSERT INTO TORDER_INTF_WMS_STOCK_CLOSE (
     CTKEY
   , OWKEY
   , OLNICKEY
   , AVQTY
   , OBEXPCTQTY
   , REQUESTDT
   , IFID
   , INSERTDATE
   , INSERTURKEY
   , UPDATEDATE
   , UPDATEURKEY
) VALUES (
     #{ctkey}
   , #{owkey}
   , #{olnickey}
   , #{avqty}
   , #{obexpctqty}
   , #{requestDt}
   , #{ifid}
   , TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
   , #{interfaceUrkey}
   , TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
   , #{interfaceUrkey}
)

/* oms-ordercommon-sql-oracle.xml - insertIntfStockCloseOmsToMall */
INSERT INTO TORDER_INTF_MAL_STOCK_CLOSE (
     ICKEY
   , OLNICKEY
   , STCKQTY
   , DLVPARMQTY
   , REQUESTDT
   , IFID
   , INSERTDATE
   , INSERTURKEY
   , UPDATEDATE
   , UPDATEURKEY
) VALUES (
     #{ickey}
   , #{olnickey}
   , #{stckqty}
   , #{dlvparmqty}
   , #{requestDt}
   , #{ifid}
   , TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
   , #{interfaceUrkey}
   , TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
   , #{interfaceUrkey}
)
